package com.talhanation.recruits.rrextra;

import com.talhanation.recruits.Main;
import net.minecraft.server.level.ServerLevel;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;

public class MarketManager {
    private static final List<MarketOffer> activeOffers = new ArrayList<>();

    public static void load(ServerLevel level) {
        MarketSavedData data = MarketSavedData.get(level);
        activeOffers.clear();
        activeOffers.addAll(data.getOffers());
        Main.LOGGER.info("RRExtra: Loaded " + activeOffers.size() + " market offers from disk.");
    }

    public static void save(ServerLevel level) {
        MarketSavedData data = MarketSavedData.get(level);
        data.setOffers(new ArrayList<>(activeOffers));
        Main.LOGGER.info("RRExtra: Saved " + activeOffers.size() + " market offers to disk.");
    }

    public static void addOffer(ServerLevel level, MarketOffer offer) {
        activeOffers.add(offer);
        save(level);
        Main.LOGGER.info("RRExtra: Added new offer from " + offer.getSellerUUID() + ". Total: " + activeOffers.size());
    }

    public static void removeOffer(ServerLevel level, UUID offerID) {
        activeOffers.removeIf(offer -> offer.getOfferID().equals(offerID));
        save(level);
    }

    public static List<MarketOffer> getOffers() {
        return new ArrayList<>(activeOffers);
    }

    public static List<MarketOffer> getOnlineOffers(ServerLevel level) {
        List<MarketOffer> online = activeOffers.stream()
                .filter(offer -> level.getServer().getPlayerList().getPlayer(offer.getSellerUUID()) != null)
                .collect(Collectors.toList());
        Main.LOGGER.info("RRExtra: Found " + online.size() + " online offers (Total active: " + activeOffers.size() + ")");
        return online;
    }

    public static MarketOffer getOffer(UUID offerID) {
        return activeOffers.stream()
                .filter(offer -> offer.getOfferID().equals(offerID))
                .findFirst()
                .orElse(null);
    }
}

