package com.talhanation.recruits.rrextra.network;

import com.talhanation.recruits.Main;
import com.talhanation.recruits.rrextra.MarketOffer;
import de.maxhenkel.corelib.net.Message;
import net.minecraft.network.FriendlyByteBuf;
import net.minecraftforge.api.distmarker.Dist;
import net.minecraftforge.api.distmarker.OnlyIn;
import net.minecraftforge.network.NetworkEvent;
import java.util.ArrayList;
import java.util.List;

public class MessageSyncMarket implements Message<MessageSyncMarket> {
    private List<MarketOffer> offers;

    public MessageSyncMarket() {
    }

    public MessageSyncMarket(List<MarketOffer> offers) {
        this.offers = offers;
    }

    @Override
    public Dist getExecutingSide() {
        return Dist.CLIENT;
    }

    @Override
    @OnlyIn(Dist.CLIENT)
    public void executeClientSide(NetworkEvent.Context context) {
        context.enqueueWork(() -> {
            Main.LOGGER.info("RRExtra: Received MessageSyncMarket with " + offers.size() + " offers.");
            com.talhanation.recruits.rrextra.client.MarketClientManager.setOffers(offers);
            com.talhanation.recruits.rrextra.client.MarketClientManager.openMarketScreen();
        });
    }

    @Override
    public MessageSyncMarket fromBytes(FriendlyByteBuf buf) {
        int size = buf.readInt();
        this.offers = new ArrayList<>();
        for (int i = 0; i < size; i++) {
            this.offers.add(MarketOffer.fromNBT(buf.readNbt()));
        }
        return this;
    }

    @Override
    public void toBytes(FriendlyByteBuf buf) {
        buf.writeInt(offers.size());
        for (MarketOffer offer : offers) {
            buf.writeNbt(offer.toNBT());
        }
    }
}

