package com.talhanation.recruits.rrextra;

import net.minecraft.nbt.CompoundTag;
import net.minecraft.nbt.ListTag;
import net.minecraft.nbt.Tag;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

public class MarketOffer {
    private final UUID offerID;
    private final UUID sellerUUID;
    private final String sellerName;
    private final int price;
    private final List<CompoundTag> recruitData;

    public MarketOffer(UUID sellerUUID, String sellerName, int price, List<CompoundTag> recruitData) {
        this.offerID = UUID.randomUUID();
        this.sellerUUID = sellerUUID;
        this.sellerName = sellerName;
        this.price = price;
        this.recruitData = recruitData;
    }

    public MarketOffer(UUID offerID, UUID sellerUUID, String sellerName, int price, List<CompoundTag> recruitData) {
        this.offerID = offerID;
        this.sellerUUID = sellerUUID;
        this.sellerName = sellerName;
        this.price = price;
        this.recruitData = recruitData;
    }

    public UUID getOfferID() {
        return offerID;
    }

    public UUID getSellerUUID() {
        return sellerUUID;
    }

    public String getSellerName() {
        return sellerName;
    }

    public int getPrice() {
        return price;
    }

    public List<CompoundTag> getRecruitData() {
        return recruitData;
    }

    public CompoundTag toNBT() {
        CompoundTag nbt = new CompoundTag();
        nbt.putUUID("OfferID", offerID);
        nbt.putUUID("SellerUUID", sellerUUID);
        nbt.putString("SellerName", sellerName);
        nbt.putInt("Price", price);

        ListTag recruitList = new ListTag();
        for (CompoundTag recruit : recruitData) {
            recruitList.add(recruit);
        }
        nbt.put("Recruits", recruitList);
        return nbt;
    }

    public static MarketOffer fromNBT(CompoundTag nbt) {
        UUID offerID = nbt.getUUID("OfferID");
        UUID sellerUUID = nbt.getUUID("SellerUUID");
        String sellerName = nbt.getString("SellerName");
        if (sellerName.isEmpty()) sellerName = "Unknown";
        int price = nbt.getInt("Price");

        ListTag recruitList = nbt.getList("Recruits", Tag.TAG_COMPOUND);
        List<CompoundTag> recruitData = new ArrayList<>();
        for (int i = 0; i < recruitList.size(); i++) {
            recruitData.add(recruitList.getCompound(i));
        }
        return new MarketOffer(offerID, sellerUUID, sellerName, price, recruitData);
    }
}

