package com.talhanation.recruits.rrextra.network;

import com.talhanation.recruits.Main;
import com.talhanation.recruits.ClaimEvents;
import com.talhanation.recruits.FactionEvents;
import com.talhanation.recruits.rrextra.MarketManager;
import com.talhanation.recruits.rrextra.MarketOffer;
import com.talhanation.recruits.config.RecruitsServerConfig;
import com.talhanation.recruits.entities.AbstractRecruitEntity;
import com.talhanation.recruits.world.RecruitsClaim;
import de.maxhenkel.corelib.net.Message;
import net.minecraft.ChatFormatting;
import net.minecraft.nbt.CompoundTag;
import net.minecraft.network.FriendlyByteBuf;
import net.minecraft.network.chat.Component;
import net.minecraft.resources.ResourceLocation;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.entity.Entity;
import net.minecraft.world.entity.EntityType;
import net.minecraft.world.item.Item;
import net.minecraft.world.item.ItemStack;
import net.minecraft.world.scores.Team;
import net.minecraftforge.api.distmarker.Dist;
import net.minecraftforge.network.NetworkEvent;
import net.minecraftforge.registries.ForgeRegistries;
import java.util.Objects;
import java.util.Optional;
import java.util.UUID;

public class MessageBuyOffer implements Message<MessageBuyOffer> {
    private UUID offerID;

    public MessageBuyOffer() {
    }

    public MessageBuyOffer(UUID offerID) {
        this.offerID = offerID;
    }

    @Override
    public Dist getExecutingSide() {
        return Dist.DEDICATED_SERVER;
    }

    @Override
    public void executeServerSide(NetworkEvent.Context context) {
        context.enqueueWork(() -> {
            ServerPlayer buyer = Objects.requireNonNull(context.getSender());

            // SIEGE CHECK
            if (isUnderSiege(buyer)) {
                buyer.sendSystemMessage(Component.literal("You cannot buy recruits while your kingdom is under siege!").withStyle(ChatFormatting.RED));
                return;
            }

            MarketOffer offer = MarketManager.getOffer(offerID);

            if (offer == null) {
                buyer.sendSystemMessage(Component.literal("This offer is no longer available!").withStyle(ChatFormatting.RED));
                return;
            }

            if (buyer.getUUID().equals(offer.getSellerUUID())) {
                buyer.sendSystemMessage(Component.literal("You cannot buy your own recruits!").withStyle(ChatFormatting.RED));
                return;
            }

            ServerPlayer seller = buyer.serverLevel().getServer().getPlayerList().getPlayer(offer.getSellerUUID());
            if (seller == null) {
                buyer.sendSystemMessage(Component.literal("Seller is offline!").withStyle(ChatFormatting.RED));
                return;
            }

            ResourceLocation currencyId = new ResourceLocation(RecruitsServerConfig.RecruitCurrency.get());
            Item currencyItem = ForgeRegistries.ITEMS.getValue(currencyId);
            int price = offer.getPrice();

            if (buyer.getInventory().countItem(currencyItem) < price) {
                buyer.sendSystemMessage(Component.literal("You don't have enough " + (currencyItem != null ? currencyItem.getDescription().getString() : "currency") + "!").withStyle(ChatFormatting.RED));
                return;
            }

            // 1. Subtract Currency from Buyer
            int remaining = price;
            for (int i = 0; i < buyer.getInventory().getContainerSize(); i++) {
                ItemStack stack = buyer.getInventory().getItem(i);
                if (stack.getItem().equals(currencyItem)) {
                    int toRemove = Math.min(stack.getCount(), remaining);
                    stack.shrink(toRemove);
                    remaining -= toRemove;
                    if (remaining <= 0) break;
                }
            }

            // 2. Add Currency to Seller
            ItemStack payment = new ItemStack(currencyItem, price);
            if (!seller.getInventory().add(payment)) {
                seller.drop(payment, false);
            }

            // 3. Spawn Recruits for Buyer
            for (CompoundTag nbt : offer.getRecruitData()) {
                Optional<Entity> entityOpt = EntityType.create(nbt, buyer.serverLevel());
                entityOpt.ifPresent(entity -> {
                    if (entity instanceof AbstractRecruitEntity recruit) {
                        recruit.setIsOwned(true);
                        recruit.setOwnerUUID(Optional.of(buyer.getUUID()));
                        recruit.teleportTo(buyer.getX(), buyer.getY(), buyer.getZ());
                        buyer.serverLevel().addFreshEntity(recruit);
                    }
                });
            }

            // 4. Cleanup
            MarketManager.removeOffer(buyer.serverLevel(), offerID);
            buyer.sendSystemMessage(Component.literal("Successfully bought recruits from " + seller.getName().getString() + "!").withStyle(ChatFormatting.GREEN));
            seller.sendSystemMessage(Component.literal(buyer.getName().getString() + " bought your listed recruits!").withStyle(ChatFormatting.GREEN));
        });
    }

    private boolean isUnderSiege(ServerPlayer player) {
        Team team = player.getTeam();
        if (team == null) return false;

        String factionID = team.getName();
        if (ClaimEvents.recruitsClaimManager == null) return false;

        for (RecruitsClaim claim : ClaimEvents.recruitsClaimManager.getAllClaims()) {
            if (claim.isUnderSiege && claim.getOwnerFaction() != null && claim.getOwnerFaction().getStringID().equals(factionID)) {
                return true;
            }
        }
        return false;
    }

    @Override
    public MessageBuyOffer fromBytes(FriendlyByteBuf buf) {
        this.offerID = buf.readUUID();
        return this;
    }

    @Override
    public void toBytes(FriendlyByteBuf buf) {
        buf.writeUUID(offerID);
    }
}

