- [ ] **Step 1: Create the Economy Manager**
Define the singleton that manages active agreements and pending requests with expiry logic.

```java
package com.talhanation.recruits.rrextra;

import net.minecraft.server.level.ServerLevel;
import java.util.*;

public class RecruitsEconomyManager {
    private static Map<String, Long> activeAgreements = new HashMap<>();
    private static Map<String, Long> pendingRequests = new HashMap<>();

    public static void load(ServerLevel level) {
        RecruitsEconomySaveData data = RecruitsEconomySaveData.get(level);
        activeAgreements = data.getActiveAgreements();
        pendingRequests = data.getPendingRequests();
    }

    public static void save(ServerLevel level) {
        RecruitsEconomySaveData data = RecruitsEconomySaveData.get(level);
        data.setEconomyData(activeAgreements, pendingRequests);
    }

    public static String makeKey(String f1, String f2) {
        String[] sorted = {f1, f2};
        Arrays.sort(sorted);
        return sorted[0] + "|" + sorted[1];
    }

    public static boolean hasTrade(String f1, String f2) {
        return activeAgreements.containsKey(makeKey(f1, f2));
    }

    public static void addRequest(String initiator, String target) {
        pendingRequests.put(initiator + "|" + target, System.currentTimeMillis() + 86400000L);
    }

    public static void acceptRequest(String initiator, String target, ServerLevel level) {
        pendingRequests.remove(initiator + "|" + target);
        activeAgreements.put(makeKey(initiator, target), System.currentTimeMillis());
        save(level);
    }

    public static Map<String, Long> getActiveAgreements() { return activeAgreements; }
    public static Map<String, Long> getPendingRequests() { return pendingRequests; }
}
```

