public static int getStock(ServerLevel level, ItemMarketOffer offer) {
    BlockPos pos = offer.getStockChestPos();
    // Force load chunk temporarily if needed
    level.getChunk(pos); 

    net.minecraft.world.level.block.entity.BlockEntity be = level.getBlockEntity(pos);
    if (be != null) {
        net.minecraftforge.common.util.LazyOptional<net.minecraftforge.items.IItemHandler> handler = be.getCapability(net.minecraftforge.common.capabilities.ForgeCapabilities.ITEM_HANDLER, null);
        if (handler.isPresent()) {
            int count = 0;
            net.minecraftforge.items.IItemHandler items = handler.orElse(null);
            for (int i = 0; i < items.getSlots(); i++) {
                net.minecraft.world.item.ItemStack stack = items.getStackInSlot(i);
                if (net.minecraftforge.registries.ForgeRegistries.ITEMS.getKey(stack.getItem()).toString().equals(offer.getItemID())) {
                    count += stack.getCount();
                }
            }
            return count;
        }
    }
    return 0;
}

