package com.talhanation.recruits.rrextra;

import net.minecraft.core.BlockPos;
import net.minecraft.nbt.CompoundTag;

public class ItemMarketOffer {
    private String itemID;
    private CompoundTag itemNbt; // Added NBT storage
    private int price;
    private String sellerFactionID;
    private BlockPos stockChestPos;

    public ItemMarketOffer(String itemID, CompoundTag itemNbt, int price, String sellerFactionID, BlockPos stockChestPos) {
        this.itemID = itemID;
        this.itemNbt = itemNbt;
        this.price = price;
        this.sellerFactionID = sellerFactionID;
        this.stockChestPos = stockChestPos;
    }

    public String getItemID() {
        return itemID;
    }

    public CompoundTag getItemNbt() {
        return itemNbt;
    }

    public int getPrice() {
        return price;
    }

    public String getSellerFactionID() {
        return sellerFactionID;
    }

    public BlockPos getStockChestPos() {
        return stockChestPos;
    }

    public CompoundTag toNBT() {
        CompoundTag nbt = new CompoundTag();
        nbt.putString("ItemID", itemID);
        if (itemNbt != null) {
            nbt.put("ItemNbt", itemNbt);
        }
        nbt.putInt("Price", price);
        nbt.putString("SellerFactionID", sellerFactionID);
        nbt.putLong("StockChestPos", stockChestPos.asLong());
        return nbt;
    }

    public static ItemMarketOffer fromNBT(CompoundTag nbt) {
        return new ItemMarketOffer(
                nbt.getString("ItemID"),
                nbt.contains("ItemNbt") ? nbt.getCompound("ItemNbt") : null,
                nbt.getInt("Price"),
                nbt.getString("SellerFactionID"),
                BlockPos.of(nbt.getLong("StockChestPos"))
        );
    }
}

