        net.minecraftforge.common.util.LazyOptional<net.minecraftforge.items.IItemHandler> handler = be.getCapability(net.minecraftforge.common.capabilities.ForgeCapabilities.ITEM_HANDLER, null);
        if (handler.isPresent()) {
