import net.minecraftforge.event.level.BlockEvent;
import net.minecraftforge.event.level.BlockEvent.SignChangeEvent;
import net.minecraftforge.eventbus.api.SubscribeEvent;

args.content:
package com.talhanation.recruits.rrextra;

import com.talhanation.recruits.FactionEvents;
import com.talhanation.recruits.ClaimEvents;
import com.talhanation.recruits.world.RecruitsFaction;
import com.talhanation.recruits.world.RecruitsClaim;
import net.minecraft.ChatFormatting;
import net.minecraft.core.BlockPos;
import net.minecraft.core.Direction;
import net.minecraft.nbt.CompoundTag;
import net.minecraft.network.chat.ClickEvent;
import net.minecraft.network.chat.Component;
import net.minecraft.network.chat.HoverEvent;
import net.minecraft.network.chat.MutableComponent;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.tags.BlockTags;
import net.minecraft.world.level.ChunkPos;
import net.minecraft.world.level.block.WallSignBlock;
import net.minecraft.world.level.block.entity.SignBlockEntity;
import net.minecraft.world.level.block.state.BlockState;
import net.minecraft.world.scores.Team;
import net.minecraftforge.event.TickEvent;
import net.minecraftforge.event.entity.EntityJoinLevelEvent;
import net.minecraftforge.event.level.BlockEvent;
import net.minecraftforge.eventbus.api.SubscribeEvent;

import java.util.Iterator;
import java.util.List;
import java.util.Map;

public class EconomyEvents {
    private static int tickCounter = 0;

    @SubscribeEvent
    public void onSignPlaced(BlockEvent.EntityPlaceEvent event) {
        if (event.getLevel().isClientSide() || !(event.getEntity() instanceof ServerPlayer player)) return;

        BlockPos pos = event.getPos();
        ServerLevel level = player.serverLevel();
        BlockState state = event.getPlacedBlock();

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
            if (sign != null) {
                checkPapelSign(player, level, pos, state, sign.getFrontText().getMessage(0, true).getString());
            }
        }
    }

    @SubscribeEvent
    public void onSignChange(BlockEvent.SignChangeEvent event) {
        if (event.getLevel().isClientSide() || !(event.getPlayer() instanceof ServerPlayer player)) return;

        BlockPos pos = event.getPos();
        ServerLevel level = player.serverLevel();
        BlockState state = level.getBlockState(pos);

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            checkPapelSign(player, level, pos, state, event.getLine(0).getString());
        }
    }

    private void checkPapelSign(ServerPlayer player, ServerLevel level, BlockPos pos, BlockState state, String firstLine) {
        if (firstLine.equals("PAPEL")) {
            if (player.getTeam() == null) {
                player.sendSystemMessage(Component.literal("You must be in a faction to setup a Bank!").withStyle(ChatFormatting.RED));
                return;
            }

            String factionID = player.getTeam().getName();
            ChunkPos chunkPos = new ChunkPos(pos);
            RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

            if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
                player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Bank!").withStyle(ChatFormatting.RED));
                return;
            }

            BlockPos attachedPos;
            if (state.getBlock() instanceof WallSignBlock) {
                Direction facing = state.getValue(WallSignBlock.FACING);
                attachedPos = pos.relative(facing.getOpposite());
            } else {
                attachedPos = pos.below();
            }

            if (level.getBlockState(attachedPos).is(BlockTags.CHESTS)) {
                RecruitsEconomyManager.addBankChest(factionID, attachedPos, level);
                player.sendSystemMessage(Component.literal("Bank Chest registered successfully!").withStyle(ChatFormatting.GREEN));
            } else {
                player.sendSystemMessage(Component.literal("The PAPEL sign must be attached to a chest!").withStyle(ChatFormatting.RED));
            }
        } else {
            // Check for Market Sign NBT
            SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
            if (sign != null) {
                CompoundTag nbt = sign.saveWithFullMetadata();
                if (nbt.contains("MarketItem")) {
                    String itemID = nbt.getString("MarketItem");
                    int price = nbt.getInt("MarketPrice");

                    Team team = player.getTeam();
                    if (team == null) {
                        player.sendSystemMessage(Component.literal("You must be in a faction to list items!").withStyle(ChatFormatting.RED));
                        return;
                    }

                    String factionID = team.getName();
                    ChunkPos chunkPos = new ChunkPos(pos);
                    RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

                    if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
                        player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Shop!").withStyle(ChatFormatting.RED));
                        return;
                    }

                    BlockPos attachedPos;
                    if (state.getBlock() instanceof WallSignBlock) {
                        Direction facing = state.getValue(WallSignBlock.FACING);
                        attachedPos = pos.relative(facing.getOpposite());
                    } else {
                        attachedPos = pos.below();
                    }

                    if (level.getBlockState(attachedPos).is(BlockTags.CHESTS)) {
                        CompoundTag itemNbt = nbt.contains("ItemNbt") ? nbt.getCompound("ItemNbt") : null;
                        ItemMarketOffer offer = new ItemMarketOffer(itemID, itemNbt, price, factionID, attachedPos);
                        RecruitsEconomyManager.addMarketOffer(pos, offer, level);

                        // Update Sign Text
                        String itemName = new net.minecraft.world.item.ItemStack(net.minecraftforge.registries.ForgeRegistries.ITEMS.getValue(new net.minecraft.resources.ResourceLocation(itemID))).getHoverName().getString();

                        sign.getFrontText().setMessage(0, Component.literal("[Market]").withStyle(ChatFormatting.GOLD));
                        sign.getFrontText().setMessage(1, Component.literal(itemName));
                        sign.getFrontText().setMessage(2, Component.literal(price + " Emeralds").withStyle(ChatFormatting.GREEN));
                        sign.getFrontText().setMessage(3, team.getDisplayName());

                        // Critical for syncing sign text to all players
                        level.sendBlockUpdated(pos, state, state, 3);
                        sign.setChanged();

                        player.sendSystemMessage(Component.literal("Market Shop registered successfully!").withStyle(ChatFormatting.GREEN));
                    } else {
                        player.sendSystemMessage(Component.literal("The Market sign must be attached to a chest!").withStyle(ChatFormatting.RED));
                    }
                }
            }
        }
    }

    @SubscribeEvent
    public void onBlockBreak(BlockEvent.BreakEvent event) {
        if (event.getLevel().isClientSide() || !(event.getLevel() instanceof ServerLevel level)) return;

        BlockPos pos = event.getPos();
        BlockState state = event.getState();

        // 1. Handle Sign breaking
        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            // Check Market Offer
            if (RecruitsEconomyManager.getMarketOffers().containsKey(pos)) {
                ItemMarketOffer offer = RecruitsEconomyManager.getMarketOffers().get(pos);
                String factionID = offer.getSellerFactionID();
                RecruitsEconomyManager.removeMarketOffer(pos, level);
                notifyLeader(factionID, Component.literal("Your Market Shop at " + pos.toShortString() + " has been destroyed!").withStyle(ChatFormatting.RED), level);
            }

            // Check PAPEL Sign
            SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
            if (sign != null && sign.getFrontText().getMessage(0, true).getString().equals("PAPEL")) {
                BlockPos attachedPos;
                if (state.getBlock() instanceof WallSignBlock) {
                    Direction facing = state.getValue(WallSignBlock.FACING);
                    attachedPos = pos.relative(facing.getOpposite());
                } else {
                    attachedPos = pos.below();
                }

                for (Map.Entry<String, List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                    if (entry.getValue().contains(attachedPos)) {
                        String factionID = entry.getKey();
                        RecruitsEconomyManager.removeBankChest(factionID, attachedPos, level);
                        notifyLeader(factionID, Component.literal("Your Bank at " + attachedPos.toShortString() + " was removed because its PAPEL sign was broken!").withStyle(ChatFormatting.RED), level);
                        break;
                    }
                }
            }
        }

        // 2. Handle Chest breaking
        if (state.is(BlockTags.CHESTS)) {
            // Check if it's a Stock Chest
            Iterator<Map.Entry<BlockPos, ItemMarketOffer>> it = RecruitsEconomyManager.getMarketOffers().entrySet().iterator();
            boolean changed = false;
            while (it.hasNext()) {
                Map.Entry<BlockPos, ItemMarketOffer> entry = it.next();
                if (entry.getValue().getStockChestPos().equals(pos)) {
                    String factionID = entry.getValue().getSellerFactionID();
                    it.remove();
                    notifyLeader(factionID, Component.literal("Your Market Shop at " + entry.getKey().toShortString() + " was removed because its stock chest was broken!").withStyle(ChatFormatting.RED), level);
                    changed = true;
                }
            }

            if (changed) {
                RecruitsEconomyManager.save(level);
                RecruitsEconomyManager.syncAll();
            }

            // Check if it's a Bank Chest
            for (Map.Entry<String, List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                if (entry.getValue().contains(pos)) {
                    String factionID = entry.getKey();
                    RecruitsEconomyManager.removeBankChest(factionID, pos, level);
                    notifyLeader(factionID, Component.literal("Your Bank at " + pos.toShortString() + " has been destroyed!").withStyle(ChatFormatting.RED), level);
                    break;
                }
            }
        }
    }

    private void notifyLeader(String factionID, Component message, ServerLevel level) {
        RecruitsFaction faction = FactionEvents.recruitsFactionManager.getFactionByStringID(factionID);
        if (faction != null && faction.getTeamLeaderUUID() != null) {
            ServerPlayer leader = level.getServer().getPlayerList().getPlayer(faction.getTeamLeaderUUID());
            if (leader != null) {
                leader.sendSystemMessage(message);
            }
        }
    }

    @SubscribeEvent
    public void onPlayerJoin(EntityJoinLevelEvent event) {
        if (event.getLevel().isClientSide()) return;

        if (event.getEntity() instanceof ServerPlayer player) {
            RecruitsEconomyManager.syncToPlayer(player);

            if (player.getTeam() == null) return;

            String playerFactionID = player.getTeam().getName();
            RecruitsFaction faction = FactionEvents.recruitsFactionManager.getFactionByStringID(playerFactionID);

            if (faction != null && faction.getTeamLeaderUUID().equals(player.getUUID())) {
                Map<String, Long> pendingRequests = RecruitsEconomyManager.getPendingRequests();

                for (Map.Entry<String, Long> entry : pendingRequests.entrySet()) {
                    String[] parts = entry.getKey().split("\\|");
                    if (parts.length == 2) {
                        String initiator = parts[0];
                        String target = parts[1];

                        if (target.equals(playerFactionID)) {
                            RecruitsFaction initiatorFaction = FactionEvents.recruitsFactionManager.getFactionByStringID(initiator);
                            String initiatorName = initiatorFaction != null ? initiatorFaction.getTeamDisplayName() : initiator;

                            MutableComponent message = Component.literal(initiatorName + " wants to establish a Trade Agreement! ")
                                    .withStyle(ChatFormatting.GOLD);

                            MutableComponent acceptBtn = Component.literal("[Accept] ")
                                    .withStyle(ChatFormatting.GREEN)
                                    .withStyle(s -> s.withClickEvent(new ClickEvent(ClickEvent.Action.RUN_COMMAND, "/market trade accept " + initiator))
                                            .withHoverEvent(new HoverEvent(HoverEvent.Action.SHOW_TEXT, Component.literal("Click to Accept"))));

                            MutableComponent rejectBtn = Component.literal("[Reject]")
                                    .withStyle(ChatFormatting.RED)
                                    .withStyle(s -> s.withClickEvent(new ClickEvent(ClickEvent.Action.RUN_COMMAND, "/market trade reject " + initiator))
                                            .withHoverEvent(new HoverEvent(HoverEvent.Action.SHOW_TEXT, Component.literal("Click to Reject"))));

                            player.sendSystemMessage(message.append(acceptBtn).append(rejectBtn));
                        }
                    }
                }
            }
        }
    }

    @SubscribeEvent
    public void onServerTick(TickEvent.ServerTickEvent event) {
        if (event.phase != TickEvent.Phase.END) return;

        tickCounter++;
        if (tickCounter >= 1000) {
            tickCounter = 0;

            Map<String, Long> pendingRequests = RecruitsEconomyManager.getPendingRequests();
            long currentTime = System.currentTimeMillis();
            boolean changed = false;

            Iterator<Map.Entry<String, Long>> iterator = pendingRequests.entrySet().iterator();
            while (iterator.hasNext()) {
                Map.Entry<String, Long> entry = iterator.next();
                if (currentTime > entry.getValue()) {
                    iterator.remove();
                    changed = true;
                }
            }

            if (changed) {
                RecruitsEconomyManager.save(event.getServer().overworld());
                RecruitsEconomyManager.syncAll();
            }
        }
    }
}

package com.talhanation.recruits.rrextra;

import com.talhanation.recruits.FactionEvents;
import com.talhanation.recruits.ClaimEvents;
import com.talhanation.recruits.world.RecruitsFaction;
import com.talhanation.recruits.world.RecruitsClaim;
import net.minecraft.ChatFormatting;
import net.minecraft.core.BlockPos;
import net.minecraft.core.Direction;
import net.minecraft.nbt.CompoundTag;
import net.minecraft.network.chat.ClickEvent;
import net.minecraft.network.chat.Component;
import net.minecraft.network.chat.HoverEvent;
import net.minecraft.network.chat.MutableComponent;
import net.minecraft.resources.ResourceLocation;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.tags.BlockTags;
import net.minecraft.world.level.ChunkPos;
import net.minecraft.world.level.block.WallSignBlock;
import net.minecraft.world.level.block.entity.SignBlockEntity;
import net.minecraft.world.level.block.state.BlockState;
import net.minecraft.world.scores.Team;
import net.minecraftforge.event.TickEvent;
import net.minecraftforge.event.entity.EntityJoinLevelEvent;
import net.minecraftforge.event.level.BlockEvent;
import net.minecraftforge.eventbus.api.SubscribeEvent;

import java.util.Iterator;
import java.util.List;
import java.util.Map;

public class EconomyEvents {
    private static int tickCounter = 0;

    @SubscribeEvent
    public void onSignPlaced(BlockEvent.EntityPlaceEvent event) {
        if (event.getLevel().isClientSide() || !(event.getEntity() instanceof ServerPlayer player)) return;

        BlockPos pos = event.getPos();
        ServerLevel level = player.serverLevel();
        BlockState state = event.getPlacedBlock();

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
            if (sign != null) {
                checkPapelSign(player, level, pos, state, sign.getFrontText().getMessage(0, true).getString());
            }
        }
    }

    @SubscribeEvent
    public void onSignChange(BlockEvent.SignChangeEvent event) {
        if (event.getLevel().isClientSide() || !(event.getPlayer() instanceof ServerPlayer player)) return;

        BlockPos pos = event.getPos();
        ServerLevel level = (ServerLevel) event.getLevel();
        BlockState state = level.getBlockState(pos);

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            checkPapelSign(player, level, pos, state, event.getLine(0).getString());
        }
    }

    private void checkPapelSign(ServerPlayer player, ServerLevel level, BlockPos pos, BlockState state, String firstLine) {
        if (firstLine.equals("PAPEL")) {
            if (player.getTeam() == null) {
                player.sendSystemMessage(Component.literal("You must be in a faction to setup a Bank!").withStyle(ChatFormatting.RED));
                return;
            }

            String factionID = player.getTeam().getName();
            ChunkPos chunkPos = new ChunkPos(pos);
            RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

            if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
                player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Bank!").withStyle(ChatFormatting.RED));
                return;
            }

            BlockPos attachedPos;
            if (state.getBlock() instanceof WallSignBlock) {
                Direction facing = state.getValue(WallSignBlock.FACING);
                attachedPos = pos.relative(facing.getOpposite());
            } else {
                attachedPos = pos.below();
            }

            if (level.getBlockState(attachedPos).is(BlockTags.CHESTS)) {
                RecruitsEconomyManager.addBankChest(factionID, attachedPos, level);
                player.sendSystemMessage(Component.literal("Bank Chest registered successfully!").withStyle(ChatFormatting.GREEN));
            } else {
                player.sendSystemMessage(Component.literal("The PAPEL sign must be attached to a chest!").withStyle(ChatFormatting.RED));
            }
        } else {
            // Check for Market Sign NBT
            SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
            if (sign != null) {
                CompoundTag nbt = sign.saveWithFullMetadata();
                if (nbt.contains("MarketItem")) {
                    String itemID = nbt.getString("MarketItem");
                    int price = nbt.getInt("MarketPrice");

                    Team team = player.getTeam();
                    if (team == null) {
                        player.sendSystemMessage(Component.literal("You must be in a faction to list items!").withStyle(ChatFormatting.RED));
                        return;
                    }

                    String factionID = team.getName();
                    ChunkPos chunkPos = new ChunkPos(pos);
                    RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

                    if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
                        player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Shop!").withStyle(ChatFormatting.RED));
                        return;
                    }

                    BlockPos attachedPos;
                    if (state.getBlock() instanceof WallSignBlock) {
                        Direction facing = state.getValue(WallSignBlock.FACING);
                        attachedPos = pos.relative(facing.getOpposite());
                    } else {
                        attachedPos = pos.below();
                    }

                    if (level.getBlockState(attachedPos).is(BlockTags.CHESTS)) {
                        CompoundTag itemNbt = nbt.contains("ItemNbt") ? nbt.getCompound("ItemNbt") : null;
                        ItemMarketOffer offer = new ItemMarketOffer(itemID, itemNbt, price, factionID, attachedPos);
                        RecruitsEconomyManager.addMarketOffer(pos, offer, level);

                        // Update Sign Text
                        ResourceLocation resLoc = ResourceLocation.tryParse(itemID);
                        String itemName = itemID;
                        if (resLoc != null && net.minecraftforge.registries.ForgeRegistries.ITEMS.containsKey(resLoc)) {
                            itemName = new net.minecraft.world.item.ItemStack(net.minecraftforge.registries.ForgeRegistries.ITEMS.getValue(resLoc)).getHoverName().getString();
                        }

                        sign.getFrontText().setMessage(0, Component.literal("[Market]").withStyle(ChatFormatting.GOLD));
                        sign.getFrontText().setMessage(1, Component.literal(itemName));
                        sign.getFrontText().setMessage(2, Component.literal(price + " Emeralds").withStyle(ChatFormatting.GREEN));
                        sign.getFrontText().setMessage(3, team.getDisplayName());

                        // Critical for syncing sign text to all players
                        level.sendBlockUpdated(pos, state, state, 3);
                        sign.setChanged();

                        player.sendSystemMessage(Component.literal("Market Shop registered successfully!").withStyle(ChatFormatting.GREEN));
                    } else {
                        player.sendSystemMessage(Component.literal("The Market sign must be attached to a chest!").withStyle(ChatFormatting.RED));
                    }
                }
            }
        }
    }

    @SubscribeEvent
    public void onBlockBreak(BlockEvent.BreakEvent event) {
        if (event.getLevel().isClientSide() || !(event.getLevel() instanceof ServerLevel level)) return;

        BlockPos pos = event.getPos();
        BlockState state = event.getState();

        // 1. Handle Sign breaking
        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            // Check Market Offer
            if (RecruitsEconomyManager.getMarketOffers().containsKey(pos)) {
                ItemMarketOffer offer = RecruitsEconomyManager.getMarketOffers().get(pos);
                String factionID = offer.getSellerFactionID();
                RecruitsEconomyManager.removeMarketOffer(pos, level);
                notifyLeader(factionID, Component.literal("Your Market Shop at " + pos.toShortString() + " has been destroyed!").withStyle(ChatFormatting.RED), level);
            }

            // Check PAPEL Sign
            SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
            if (sign != null && sign.getFrontText().getMessage(0, true).getString().equals("PAPEL")) {
                BlockPos attachedPos;
                if (state.getBlock() instanceof WallSignBlock) {
                    Direction facing = state.getValue(WallSignBlock.FACING);
                    attachedPos = pos.relative(facing.getOpposite());
                } else {
                    attachedPos = pos.below();
                }

                for (Map.Entry<String, List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                    if (entry.getValue().contains(attachedPos)) {
                        String factionID = entry.getKey();
                        RecruitsEconomyManager.removeBankChest(factionID, attachedPos, level);
                        notifyLeader(factionID, Component.literal("Your Bank at " + attachedPos.toShortString() + " was removed because its PAPEL sign was broken!").withStyle(ChatFormatting.RED), level);
                        break;
                    }
                }
            }
        }

        // 2. Handle Chest breaking
        if (state.is(BlockTags.CHESTS)) {
            // Check if it's a Stock Chest
            Iterator<Map.Entry<BlockPos, ItemMarketOffer>> it = RecruitsEconomyManager.getMarketOffers().entrySet().iterator();
            boolean changed = false;
            while (it.hasNext()) {
                Map.Entry<BlockPos, ItemMarketOffer> entry = it.next();
                if (entry.getValue().getStockChestPos().equals(pos)) {
                    String factionID = entry.getValue().getSellerFactionID();
                    it.remove();
                    notifyLeader(factionID, Component.literal("Your Market Shop at " + entry.getKey().toShortString() + " was removed because its stock chest was broken!").withStyle(ChatFormatting.RED), level);
                    changed = true;
                }
            }

            if (changed) {
                RecruitsEconomyManager.save(level);
                RecruitsEconomyManager.syncAll();
            }

            // Check if it's a Bank Chest
            for (Map.Entry<String, List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                if (entry.getValue().contains(pos)) {
                    String factionID = entry.getKey();
                    RecruitsEconomyManager.removeBankChest(factionID, pos, level);
                    notifyLeader(factionID, Component.literal("Your Bank at " + pos.toShortString() + " has been destroyed!").withStyle(ChatFormatting.RED), level);
                    break;
                }
            }
        }
    }

    private void notifyLeader(String factionID, Component message, ServerLevel level) {
        RecruitsFaction faction = FactionEvents.recruitsFactionManager.getFactionByStringID(factionID);
        if (faction != null && faction.getTeamLeaderUUID() != null) {
            ServerPlayer leader = level.getServer().getPlayerList().getPlayer(faction.getTeamLeaderUUID());
            if (leader != null) {
                leader.sendSystemMessage(message);
            }
        }
    }

    @SubscribeEvent
    public void onPlayerJoin(EntityJoinLevelEvent event) {
        if (event.getLevel().isClientSide()) return;

        if (event.getEntity() instanceof ServerPlayer player) {
            RecruitsEconomyManager.syncToPlayer(player);

            if (player.getTeam() == null) return;

            String playerFactionID = player.getTeam().getName();
            RecruitsFaction faction = FactionEvents.recruitsFactionManager.getFactionByStringID(playerFactionID);

            if (faction != null && faction.getTeamLeaderUUID().equals(player.getUUID())) {
                Map<String, Long> pendingRequests = RecruitsEconomyManager.getPendingRequests();

                for (Map.Entry<String, Long> entry : pendingRequests.entrySet()) {
                    String[] parts = entry.getKey().split("\\|");
                    if (parts.length == 2) {
                        String initiator = parts[0];
                        String target = parts[1];

                        if (target.equals(playerFactionID)) {
                            RecruitsFaction initiatorFaction = FactionEvents.recruitsFactionManager.getFactionByStringID(initiator);
                            String initiatorName = initiatorFaction != null ? initiatorFaction.getTeamDisplayName() : initiator;

                            MutableComponent message = Component.literal(initiatorName + " wants to establish a Trade Agreement! ")
                                    .withStyle(ChatFormatting.GOLD);

                            MutableComponent acceptBtn = Component.literal("[Accept] ")
                                    .withStyle(ChatFormatting.GREEN)
                                    .withStyle(s -> s.withClickEvent(new ClickEvent(ClickEvent.Action.RUN_COMMAND, "/market trade accept " + initiator))
                                            .withHoverEvent(new HoverEvent(HoverEvent.Action.SHOW_TEXT, Component.literal("Click to Accept"))));

                            MutableComponent rejectBtn = Component.literal("[Reject]")
                                    .withStyle(ChatFormatting.RED)
                                    .withStyle(s -> s.withClickEvent(new ClickEvent(ClickEvent.Action.RUN_COMMAND, "/market trade reject " + initiator))
                                            .withHoverEvent(new HoverEvent(HoverEvent.Action.SHOW_TEXT, Component.literal("Click to Reject"))));

                            player.sendSystemMessage(message.append(acceptBtn).append(rejectBtn));
                        }
                    }
                }
            }
        }
    }

    @SubscribeEvent
    public void onServerTick(TickEvent.ServerTickEvent event) {
        if (event.phase != TickEvent.Phase.END) return;

        tickCounter++;
        if (tickCounter >= 1000) {
            tickCounter = 0;

            Map<String, Long> pendingRequests = RecruitsEconomyManager.getPendingRequests();
            long currentTime = System.currentTimeMillis();
            boolean changed = false;

            Iterator<Map.Entry<String, Long>> iterator = pendingRequests.entrySet().iterator();
            while (iterator.hasNext()) {
                Map.Entry<String, Long> entry = iterator.next();
                if (currentTime > entry.getValue()) {
                    iterator.remove();
                    changed = true;
                }
            }

            if (changed) {
                RecruitsEconomyManager.save(event.getServer().overworld());
                RecruitsEconomyManager.syncAll();
            }
        }
    }
}

