                                    .withStyle(ChatFormatting.GREEN)
                                    .withStyle(s -> s.withClickEvent(new ClickEvent(ClickEvent.Action.RUN_COMMAND, "/market trade accept " + initiator))
                                            .withHoverEvent(new HoverEvent(HoverEvent.Action.SHOW_TEXT, Component.literal("Click to Accept"))));

                            MutableComponent rejectBtn = Component.literal("[Reject]")
                                    .withStyle(ChatFormatting.RED)
                                    .withStyle(s -> s.withClickEvent(new ClickEvent(ClickEvent.Action.RUN_COMMAND, "/market trade reject " + initiator))
                                            .withHoverEvent(new HoverEvent(HoverEvent.Action.SHOW_TEXT, Component.literal("Click to Reject"))));

                            player.sendSystemMessage(message.append(acceptBtn).append(rejectBtn));
