package com.talhanation.recruits.rrextra.client.gui;

import com.talhanation.recruits.Main;
import com.talhanation.recruits.client.gui.widgets.ListScreenEntryBase;
import com.talhanation.recruits.client.gui.widgets.ListScreenListBase;
import com.talhanation.recruits.rrextra.network.MessageRequestSign;
import net.minecraft.client.Minecraft;
import net.minecraft.client.gui.GuiGraphics;
import net.minecraft.client.gui.components.Button;
import net.minecraft.client.gui.components.EditBox;
import net.minecraft.client.gui.narration.NarrationElementOutput;
import net.minecraft.client.gui.screens.Screen;
import net.minecraft.network.chat.Component;
import net.minecraft.resources.ResourceLocation;
import net.minecraft.world.item.Item;
import net.minecraft.world.item.ItemStack;
import net.minecraftforge.api.distmarker.Dist;
import net.minecraftforge.api.distmarker.OnlyIn;
import net.minecraftforge.registries.ForgeRegistries;

import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

@OnlyIn(Dist.CLIENT)
public class ItemSelectorScreen extends Screen {
    private ItemList itemList;
    private EditBox searchBox;
    private EditBox priceBox;
    private Item selectedItem;
    private Button confirmButton;

    public ItemSelectorScreen() {
        super(Component.literal("Item Selector"));
    }

    @Override
    protected void init() {
        super.init();

        this.searchBox = new EditBox(this.font, this.width / 2 - 100, 35, 200, 20, Component.literal("Search..."));
        this.searchBox.setResponder(text -> updateList());
        this.addRenderableWidget(this.searchBox);

        this.itemList = new ItemList(this.width, this.height, 60, this.height - 60, 24);
        this.addWidget(this.itemList);

        this.priceBox = new EditBox(this.font, this.width / 2 - 50, this.height - 50, 100, 20, Component.literal("Price"));
        this.priceBox.setVisible(false);
        this.addRenderableWidget(this.priceBox);

        this.confirmButton = Button.builder(Component.literal("Confirm Listing"), button -> confirmListing())
                .bounds(this.width / 2 + 55, this.height - 50, 100, 20)
                .build();
        this.confirmButton.visible = false;
        this.addRenderableWidget(this.confirmButton);

        this.addRenderableWidget(Button.builder(Component.literal("Back"), button -> this.onClose())
                .bounds(this.width / 2 - 160, this.height - 50, 100, 20)
                .build());

        updateList();
    }

    private void updateList() {
        String query = searchBox.getValue().toLowerCase();
        List<Item> filtered = ForgeRegistries.ITEMS.getValues().stream()
                .filter(item -> item.getDescription().getString().toLowerCase().contains(query))
                .collect(Collectors.toList());

        this.itemList.clearEntries();
        int itemsPerRow = 8;
        for (int i = 0; i < filtered.size(); i += itemsPerRow) {
            int end = Math.min(i + itemsPerRow, filtered.size());
            this.itemList.addEntry(new ItemEntry(this.itemList, filtered.subList(i, end), this));
        }
    }

    public void selectItem(Item item) {
        this.selectedItem = item;
        this.priceBox.setVisible(true);
        this.confirmButton.visible = true;
        this.priceBox.setFocused(true);
    }

    private void confirmListing() {
        if (selectedItem != null) {
            try {
                int price = Integer.parseInt(priceBox.getValue());
                if (price > 0) {
                    ResourceLocation id = ForgeRegistries.ITEMS.getKey(selectedItem);
                    if (id != null) {
                        Main.SIMPLE_CHANNEL.sendToServer(new MessageRequestSign(id.toString(), price));
                        this.onClose();
                    }
                }
            } catch (NumberFormatException ignored) {
            }
        }
    }

    @Override
    public void render(GuiGraphics guiGraphics, int mouseX, int mouseY, float partialTick) {
        this.renderBackground(guiGraphics);
        this.itemList.render(guiGraphics, mouseX, mouseY, partialTick);
        guiGraphics.drawCenteredString(this.font, this.title, this.width / 2, 10, 16777215);

        if (selectedItem != null) {
            guiGraphics.drawString(this.font, "Selected: " + selectedItem.getDescription().getString(), this.width / 2 - 100, this.height - 70, 0xAAAAAA);
        }

        super.render(guiGraphics, mouseX, mouseY, partialTick);
    }

    @Override
    public boolean isPauseScreen() {
        return false;
    }

    @OnlyIn(Dist.CLIENT)
    public static class ItemList extends ListScreenListBase<ItemEntry> {
        public ItemList(int width, int height, int top, int bottom, int itemHeight) {
            super(width, height, top, bottom, itemHeight);
        }

        @Override
        public int addEntry(ItemEntry entry) {
            return super.addEntry(entry);
        }

        @Override
        public void updateNarration(NarrationElementOutput output) {
        }

        public void clearEntries() {
            super.clearEntries();
        }
    }

    @OnlyIn(Dist.CLIENT)
    public static class ItemEntry extends ListScreenEntryBase<ItemEntry> {
        private final List<Item> items;
        private final ItemSelectorScreen parent;
        private final ItemList list;
        private int lastTop;
        private int lastLeft;

        public ItemEntry(ItemList list, List<Item> items, ItemSelectorScreen parent) {
            this.list = list;
            this.items = items;
            this.parent = parent;
        }

        @Override
        public void render(GuiGraphics guiGraphics, int index, int top, int left, int width, int height, int mouseX, int mouseY, boolean isMouseOver, float partialTick) {
            this.lastTop = top;
            this.lastLeft = left;
            for (int i = 0; i < items.size(); i++) {
                Item item = items.get(i);
                int x = left + 5 + i * 22;
                int y = top + 2;

                guiGraphics.renderItem(new ItemStack(item), x, y);

                if (mouseX >= x && mouseX < x + 16 && mouseY >= y && mouseY < y + 16) {
                    guiGraphics.renderTooltip(Minecraft.getInstance().font, new ItemStack(item), mouseX, mouseY);
                }
            }
        }

        @Override
        public boolean mouseClicked(double mouseX, double mouseY, int button) {
            if (button == 0) {
                for (int i = 0; i < items.size(); i++) {
                    int x = lastLeft + 5 + i * 22;
                    int y = lastTop + 2;
                    if (mouseX >= x && mouseX < x + 16 && mouseY >= y && mouseY < y + 16) {
                        parent.selectItem(items.get(i));
                        return true;
                    }
                }
            }
            return super.mouseClicked(mouseX, mouseY, button);
        }

        @Override
        public ListScreenListBase<ItemEntry> getList() {
            return list;
        }
    }
}

