package com.talhanation.recruits.rrextra.network;

import com.talhanation.recruits.FactionEvents;
import com.talhanation.recruits.Main;
import com.talhanation.recruits.config.RecruitsServerConfig;
import com.talhanation.recruits.rrextra.ItemMarketOffer;
import com.talhanation.recruits.rrextra.RecruitsEconomyManager;
import com.talhanation.recruits.world.RecruitsFaction;
import de.maxhenkel.corelib.net.Message;
import net.minecraft.ChatFormatting;
import net.minecraft.core.BlockPos;
import net.minecraft.network.FriendlyByteBuf;
import net.minecraft.network.chat.Component;
import net.minecraft.resources.ResourceLocation;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.item.Item;
import net.minecraft.world.item.ItemStack;
import net.minecraftforge.api.distmarker.Dist;
import net.minecraftforge.network.NetworkEvent;
import net.minecraftforge.registries.ForgeRegistries;
import net.minecraftforge.items.IItemHandler;
import net.minecraftforge.common.capabilities.ForgeCapabilities;

import java.util.List;
import java.util.Objects;

public class MessageBuyMarketItem implements Message<MessageBuyMarketItem> {
    private BlockPos signPos;
    private int quantity;

    public MessageBuyMarketItem() {}

    public MessageBuyMarketItem(BlockPos signPos, int quantity) {
        this.signPos = signPos;
        this.quantity = quantity;
    }

    @Override
    public Dist getExecutingSide() {
        return Dist.DEDICATED_SERVER;
    }

    @Override
    public void executeServerSide(NetworkEvent.Context context) {
        context.enqueueWork(() -> {
            ServerPlayer buyer = Objects.requireNonNull(context.getSender());
            ServerLevel level = buyer.serverLevel();

            // a. Find Offer
            ItemMarketOffer offer = RecruitsEconomyManager.getMarketOffers().get(signPos);
            if (offer == null) {
                buyer.sendSystemMessage(Component.literal("This offer is no longer available!").withStyle(ChatFormatting.RED));
                return;
            }

            // b. Ensure Chunks are loaded for atomic operation
            level.getChunk(offer.getStockChestPos());
            List<BlockPos> bankChests = RecruitsEconomyManager.getBankChests().get(offer.getSellerFactionID());
            if (bankChests != null) {
                for (BlockPos pos : bankChests) {
                    level.getChunk(pos);
                }
            }

            // c. Verify Stock (with NBT matching)
            int availableStock = RecruitsEconomyManager.getStock(level, offer);
            if (availableStock < quantity) {
                buyer.sendSystemMessage(Component.literal("Not enough stock available! (Only " + availableStock + " left)").withStyle(ChatFormatting.RED));
                return;
            }

            // d. Verify Buyer Funds
            ResourceLocation currencyId = new ResourceLocation(RecruitsServerConfig.RecruitCurrency.get());
            Item currencyItem = ForgeRegistries.ITEMS.getValue(currencyId);
            int totalPrice = offer.getPrice() * quantity;

            if (buyer.getInventory().countItem(currencyItem) < totalPrice) {
                buyer.sendSystemMessage(Component.literal("You don't have enough " + currencyItem.getDescription().getString() + "!").withStyle(ChatFormatting.RED));
                return;
            }

            // e. Verify Bank Capacity
            int totalFreeSpace = 0;
            if (bankChests != null) {
                for (BlockPos pos : bankChests) {
                    net.minecraft.world.level.block.entity.BlockEntity be = level.getBlockEntity(pos);
                    if (be != null) {
                        IItemHandler handler = be.getCapability(ForgeCapabilities.ITEM_HANDLER).orElse(null);
                        if (handler != null) {
                            for (int i = 0; i < handler.getSlots(); i++) {
                                ItemStack stack = handler.getStackInSlot(i);
                                if (stack.isEmpty()) {
                                    totalFreeSpace += currencyItem.getMaxStackSize();
                                } else if (stack.getItem().equals(currencyItem)) {
                                    totalFreeSpace += (stack.getMaxStackSize() - stack.getCount());
                                }
                            }
                        }
                    }
                }
            }

            if (totalFreeSpace < totalPrice) {
                buyer.sendSystemMessage(Component.literal("Seller's bank is full!").withStyle(ChatFormatting.RED));
                return;
            }

            // f. Execute Transfer (One Tick)

            // 1. Subtract Emeralds from buyer
            int remainingToSubtract = totalPrice;
            for (int i = 0; i < buyer.getInventory().getContainerSize(); i++) {
                ItemStack stack = buyer.getInventory().getItem(i);
                if (stack.getItem().equals(currencyItem)) {
                    int toRemove = Math.min(stack.getCount(), remainingToSubtract);
                    stack.shrink(toRemove);
                    remainingToSubtract -= toRemove;
                    if (remainingToSubtract <= 0) break;
                }
            }

            // 2. Add Emeralds to seller's bank
            int remainingToAdd = totalPrice;
            if (bankChests != null) {
                for (BlockPos pos : bankChests) {
                    net.minecraft.world.level.block.entity.BlockEntity be = level.getBlockEntity(pos);
                    if (be != null) {
                        IItemHandler handler = be.getCapability(ForgeCapabilities.ITEM_HANDLER).orElse(null);
                        if (handler != null) {
                            for (int i = 0; i < handler.getSlots(); i++) {
                                ItemStack toInsert = new ItemStack(currencyItem, remainingToAdd);
                                ItemStack leftover = handler.insertItem(i, toInsert, false);
                                int inserted = toInsert.getCount() - leftover.getCount();
                                remainingToAdd -= inserted;
                                if (remainingToAdd <= 0) break;
                            }
                        }
                    }
                    if (remainingToAdd <= 0) break;
                }
            }

            // 3. Subtract Items from stock chest (with matching)
            int remainingToExtract = quantity;
            BlockPos stockPos = offer.getStockChestPos();
            net.minecraft.world.level.block.entity.BlockEntity stockBE = level.getBlockEntity(stockPos);
            if (stockBE != null) {
                IItemHandler handler = stockBE.getCapability(ForgeCapabilities.ITEM_HANDLER).orElse(null);
                if (handler != null) {
                    for (int i = 0; i < handler.getSlots(); i++) {
                        ItemStack stack = handler.getStackInSlot(i);
                        if (RecruitsEconomyManager.isMatching(stack, offer)) {
                            int toExtract = Math.min(stack.getCount(), remainingToExtract);
                            handler.extractItem(i, toExtract, false);
                            remainingToExtract -= toExtract;
                            if (remainingToExtract <= 0) break;
                        }
                    }
                }
            }

            // 4. Give Items to buyer
            Item marketItem = ForgeRegistries.ITEMS.getValue(new ResourceLocation(offer.getItemID()));
            ItemStack purchasedStack = new ItemStack(marketItem, quantity);
            if (offer.getItemNbt() != null) {
                purchasedStack.setTag(offer.getItemNbt().copy());
            }
            if (!buyer.getInventory().add(purchasedStack)) {
                buyer.drop(purchasedStack, false);
            }

            // g. Cleanup
            String itemName = purchasedStack.getHoverName().getString();
            buyer.sendSystemMessage(Component.literal("Successfully purchased " + quantity + "x " + itemName + "!").withStyle(ChatFormatting.GREEN));

            // Notify seller (if any leader is online)
            RecruitsFaction sellerFaction = FactionEvents.recruitsFactionManager.getFactionByStringID(offer.getSellerFactionID());
            if (sellerFaction != null) {
                ServerPlayer leader = level.getServer().getPlayerList().getPlayer(sellerFaction.getTeamLeaderUUID());
                if (leader != null) {
                    leader.sendSystemMessage(Component.literal("Your shop sold " + quantity + "x " + itemName + " to " + buyer.getName().getString() + "!").withStyle(ChatFormatting.GOLD));
                }
            }

            // Trigger sync update (stock changed)
            RecruitsEconomyManager.syncAll();
        });
    }

    @Override
    public MessageBuyMarketItem fromBytes(FriendlyByteBuf buf) {
        this.signPos = buf.readBlockPos();
        this.quantity = buf.readInt();
        return this;
    }

    @Override
    public void toBytes(FriendlyByteBuf buf) {
        buf.writeBlockPos(signPos);
        buf.writeInt(quantity);
    }
}

package com.talhanation.recruits.rrextra;

import net.minecraft.core.BlockPos;
import net.minecraft.nbt.CompoundTag;
import net.minecraft.nbt.ListTag;
import net.minecraft.nbt.LongTag;
import net.minecraft.nbt.Tag;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.world.level.saveddata.SavedData;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class RecruitsEconomySaveData extends SavedData {
    private Map<String, Long> activeAgreements = new HashMap<>();
    private Map<String, Long> pendingRequests = new HashMap<>();
    private Map<String, List<BlockPos>> bankChests = new HashMap<>();
    private Map<BlockPos, ItemMarketOffer> marketOffers = new HashMap<>();

    public static RecruitsEconomySaveData get(ServerLevel level) {
        return level.getDataStorage().computeIfAbsent(RecruitsEconomySaveData::load, RecruitsEconomySaveData::new, "rrextra_economy");
    }

    public RecruitsEconomySaveData() {}

    public RecruitsEconomySaveData(CompoundTag nbt) {
        CompoundTag active = nbt.getCompound("Active");
        for (String key : active.getAllKeys()) activeAgreements.put(key, active.getLong(key));

        CompoundTag pending = nbt.getCompound("Pending");
        for (String key : pending.getAllKeys()) pendingRequests.put(key, pending.getLong(key));

        CompoundTag banks = nbt.getCompound("BankChests");
        for (String factionID : banks.getAllKeys()) {
            ListTag list = banks.getList(factionID, Tag.TAG_LONG);
            List<BlockPos> positions = new ArrayList<>();
            for (int i = 0; i < list.size(); i++) {
                Tag tag = list.get(i);
                if (tag instanceof LongTag longTag) {
                    positions.add(BlockPos.of(longTag.getAsLong()));
                }
            }
            bankChests.put(factionID, positions);
        }

        ListTag offers = nbt.getList("MarketOffers", Tag.TAG_COMPOUND);
        for (int i = 0; i < offers.size(); i++) {
            CompoundTag offerNbt = offers.getCompound(i);
            BlockPos pos = BlockPos.of(offerNbt.getLong("PosKey"));
            marketOffers.put(pos, ItemMarketOffer.fromNBT(offerNbt.getCompound("OfferData")));
        }
    }

    public static RecruitsEconomySaveData load(CompoundTag nbt) { return new RecruitsEconomySaveData(nbt); }

    @Override
    public CompoundTag save(CompoundTag nbt) {
        CompoundTag active = new CompoundTag();
        activeAgreements.forEach(active::putLong);
        nbt.put("Active", active);

        CompoundTag pending = new CompoundTag();
        pendingRequests.forEach(pending::putLong);
        nbt.put("Pending", pending);

        CompoundTag banks = new CompoundTag();
        bankChests.forEach((factionID, positions) -> {
            ListTag list = new ListTag();
            positions.forEach(pos -> list.add(LongTag.valueOf(pos.asLong())));
            banks.put(factionID, list);
        });
        nbt.put("BankChests", banks);

        ListTag offers = new ListTag();
        marketOffers.forEach((pos, offer) -> {
            CompoundTag offerNbt = new CompoundTag();
            offerNbt.putLong("PosKey", pos.asLong());
            offerNbt.put("OfferData", offer.toNBT());
            offers.add(offerNbt);
        });
        nbt.put("MarketOffers", offers);

        return nbt;
    }

    public void setEconomyData(Map<String, Long> active, Map<String, Long> pending, Map<String, List<BlockPos>> banks, Map<BlockPos, ItemMarketOffer> offers) {
        this.activeAgreements = active;
        this.pendingRequests = pending;
        this.bankChests = banks;
        this.marketOffers = offers;
        setDirty();
    }

    public Map<String, Long> getActiveAgreements() { return activeAgreements; }
    public Map<String, Long> getPendingRequests() { return pendingRequests; }
    public Map<String, List<BlockPos>> getBankChests() { return bankChests; }
    public Map<BlockPos, ItemMarketOffer> getMarketOffers() { return marketOffers; }
}

