package com.talhanation.recruits.rrextra;

import com.talhanation.recruits.FactionEvents;
import com.talhanation.recruits.ClaimEvents;
import com.talhanation.recruits.world.RecruitsFaction;
import com.talhanation.recruits.world.RecruitsClaim;
import net.minecraft.ChatFormatting;
import net.minecraft.core.BlockPos;
import net.minecraft.core.Direction;
import net.minecraft.nbt.CompoundTag;
import net.minecraft.nbt.ListTag;
import net.minecraft.nbt.Tag;
import net.minecraft.network.chat.ClickEvent;
import net.minecraft.network.chat.Component;
import net.minecraft.network.chat.HoverEvent;
import net.minecraft.network.chat.MutableComponent;
import net.minecraft.resources.ResourceLocation;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.item.ItemStack;
import net.minecraft.world.item.SignItem;
import net.minecraft.world.level.ChunkPos;
import net.minecraft.world.level.block.Blocks;
import net.minecraft.world.level.block.WallSignBlock;
import net.minecraft.world.level.block.entity.SignBlockEntity;
import net.minecraft.world.level.block.state.BlockState;
import net.minecraft.world.scores.Team;
import net.minecraftforge.event.TickEvent;
import net.minecraftforge.event.entity.EntityJoinLevelEvent;
import net.minecraftforge.event.entity.player.PlayerInteractEvent;
import net.minecraftforge.event.level.BlockEvent;
import net.minecraftforge.eventbus.api.SubscribeEvent;

import java.util.Iterator;
import java.util.List;
import java.util.Map;

public class EconomyEvents {
    private static int tickCounter = 0;

    // Registers Market Shops instantly when the special sign is placed
    @SubscribeEvent
    public void onSignPlaced(BlockEvent.EntityPlaceEvent event) {
        if (event.getLevel().isClientSide() || !(event.getEntity() instanceof ServerPlayer player)) return;

        BlockPos pos = event.getPos();
        ServerLevel level = player.serverLevel();
        BlockState state = event.getPlacedBlock();

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            ItemStack held = player.getMainHandItem();
            if (!(held.getItem() instanceof SignItem)) held = player.getOffhandItem();

            if (held.getItem() instanceof SignItem && held.hasTag()) {
                CompoundTag tag = held.getTag();
                if (tag.contains("MarketItem")) {
                    SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
                    if (sign != null) {
                        registerMarketShop(player, level, pos, state, sign, tag);
                    }
                }
            }
        }
    }

    // Handles interaction: 
    // 1. Right-click PAPEL sign to activate bank.
    // 2. Right-click Market sign to open the buy menu.
    @SubscribeEvent
    public void onSignInteract(PlayerInteractEvent.RightClickBlock event) {
        if (event.getLevel().isClientSide() || event.getHand() != InteractionHand.MAIN_HAND || !(event.getEntity() instanceof ServerPlayer player)) return;

        BlockPos pos = event.getPos();
        ServerLevel level = (ServerLevel) event.getLevel();
        BlockState state = level.getBlockState(pos);

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
            if (sign != null) {
                // If it's a registered Market Shop, open the buy GUI
                if (RecruitsEconomyManager.getMarketOffers().containsKey(pos)) {
                    ItemMarketOffer offer = RecruitsEconomyManager.getMarketOffers().get(pos);
                    player.getServer().getCommands().performPrefixedCommand(player.createCommandSourceStack(), "eco buy " + offer.getSellerFactionID());
                    event.setCanceled(true);
                    return;
                }

                // If it's a PAPEL sign, register the bank
                String firstLine = getSignLine(sign, 0);
                if (firstLine.equalsIgnoreCase("PAPEL")) {
                    checkPapelSign(player, level, pos, state);
                    event.setCanceled(true);
                }
            }
        }
    }

    private String getSignLine(SignBlockEntity sign, int line) {
        CompoundTag nbt = sign.saveWithFullMetadata();
        if (nbt.contains("front_text")) {
            CompoundTag front = nbt.getCompound("front_text");
            if (front.contains("messages")) {
                ListTag messages = front.getList("messages", Tag.TAG_STRING);
                if (line < messages.size()) {
                    try {
                        Component comp = Component.Serializer.fromJson(messages.getString(line));
                        return comp != null ? comp.getString() : "";
                    } catch (Exception e) {
                        return messages.getString(line);
                    }
                }
            }
        }
        return "";
    }

    private void setSignText(SignBlockEntity sign, String[] lines, ChatFormatting[] colors, ServerLevel level) {
        CompoundTag nbt = sign.saveWithFullMetadata();
        CompoundTag front = nbt.contains("front_text") ? nbt.getCompound("front_text") : new CompoundTag();
        ListTag messages = new ListTag();
        for (int i = 0; i < 4; i++) {
            String text = i < lines.length ? lines[i] : "";
            ChatFormatting color = (colors != null && i < colors.length) ? colors[i] : ChatFormatting.BLACK;
            messages.add(net.minecraft.nbt.StringTag.valueOf(Component.Serializer.toJson(Component.literal(text).withStyle(color))));
        }
        front.put("messages", messages);
        nbt.put("front_text", front);
        sign.load(nbt);
        level.sendBlockUpdated(sign.getBlockPos(), sign.getBlockState(), sign.getBlockState(), 3);
    }

    private boolean isChestBlock(BlockState state) {
        return state.is(Blocks.CHEST) || state.is(Blocks.TRAPPED_CHEST) || state.is(Blocks.BARREL);
    }

    private void checkPapelSign(ServerPlayer player, ServerLevel level, BlockPos pos, BlockState state) {
        if (player.getTeam() == null) {
            player.sendSystemMessage(Component.literal("You must be in a faction to setup a Bank!").withStyle(ChatFormatting.RED));
            return;
        }

        String factionID = player.getTeam().getName();
        ChunkPos chunkPos = new ChunkPos(pos);
        RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

        if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
            player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Bank!").withStyle(ChatFormatting.RED));
            return;
        }

        BlockPos attachedPos;
        if (state.getBlock() instanceof WallSignBlock) {
            Direction facing = state.getValue(WallSignBlock.FACING);
            attachedPos = pos.relative(facing.getOpposite());
        } else {
            attachedPos = pos.below();
        }

        if (isChestBlock(level.getBlockState(attachedPos))) {
            RecruitsEconomyManager.addBankChest(factionID, attachedPos, level);
            player.sendSystemMessage(Component.literal("Bank Chest registered successfully!").withStyle(ChatFormatting.GREEN));
            setSignText((SignBlockEntity) level.getBlockEntity(pos), new String[]{"[BANK]", factionID, "Active", ""}, 
                    new ChatFormatting[]{ChatFormatting.GOLD, ChatFormatting.WHITE, ChatFormatting.GREEN, ChatFormatting.BLACK}, level);
        } else {
            player.sendSystemMessage(Component.literal("The sign must be attached to a chest!").withStyle(ChatFormatting.RED));
        }
    }

    private void registerMarketShop(ServerPlayer player, ServerLevel level, BlockPos pos, BlockState state, SignBlockEntity sign, CompoundTag nbt) {
        String itemID = nbt.getString("MarketItem");
        int price = nbt.getInt("MarketPrice");

        Team team = player.getTeam();
        if (team == null) {
            player.sendSystemMessage(Component.literal("You must be in a faction to list items!").withStyle(ChatFormatting.RED));
            return;
        }

        String factionID = team.getName();
        ChunkPos chunkPos = new ChunkPos(pos);
        RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

        if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
            player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Shop!").withStyle(ChatFormatting.RED));
            return;
        }

        BlockPos attachedPos;
        if (state.getBlock() instanceof WallSignBlock) {
            Direction facing = state.getValue(WallSignBlock.FACING);
            attachedPos = pos.relative(facing.getOpposite());
        } else {
            attachedPos = pos.below();
        }

        if (isChestBlock(level.getBlockState(attachedPos))) {
            CompoundTag itemNbt = nbt.contains("ItemNbt") ? nbt.getCompound("ItemNbt") : null;
            ItemMarketOffer offer = new ItemMarketOffer(itemID, itemNbt, price, factionID, attachedPos);
            RecruitsEconomyManager.addMarketOffer(pos, offer, level);

            String itemName = itemID;
            ResourceLocation resLoc = ResourceLocation.tryParse(itemID);
            if (resLoc != null && net.minecraftforge.registries.ForgeRegistries.ITEMS.containsKey(resLoc)) {
                itemName = new net.minecraft.world.item.ItemStack(net.minecraftforge.registries.ForgeRegistries.ITEMS.getValue(resLoc)).getHoverName().getString();
            }

            setSignText(sign, new String[]{"[Market]", itemName, price + " Emeralds", team.getName()}, 
                    new ChatFormatting[]{ChatFormatting.GOLD, ChatFormatting.WHITE, ChatFormatting.GREEN, ChatFormatting.GRAY}, level);

            player.sendSystemMessage(Component.literal("Market Shop registered successfully!").withStyle(ChatFormatting.GREEN));
        } else {
            player.sendSystemMessage(Component.literal("The Market sign must be attached to a chest!").withStyle(ChatFormatting.RED));
        }
    }

    @SubscribeEvent
    public void onBlockBreak(BlockEvent.BreakEvent event) {
        if (event.getLevel().isClientSide() || !(event.getLevel() instanceof ServerLevel level)) return;

        BlockPos pos = event.getPos();
        BlockState state = event.getState();

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            if (RecruitsEconomyManager.getMarketOffers().containsKey(pos)) {
                ItemMarketOffer offer = RecruitsEconomyManager.getMarketOffers().get(pos);
                RecruitsEconomyManager.removeMarketOffer(pos, level);
                notifyLeader(offer.getSellerFactionID(), Component.literal("Your Market Shop at " + pos.toShortString() + " has been destroyed!").withStyle(ChatFormatting.RED), level);
            }

            for (Map.Entry<String, java.util.List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                if (entry.getValue().contains(pos)) {
                    String factionID = entry.getKey();
                    RecruitsEconomyManager.removeBankChest(factionID, pos, level);
                    notifyLeader(factionID, Component.literal("Your Bank at " + pos.toShortString() + " was removed!").withStyle(ChatFormatting.RED), level);
                    break;
                }
            }
        }

        if (isChestBlock(state)) {
            Iterator<Map.Entry<BlockPos, ItemMarketOffer>> it = RecruitsEconomyManager.getMarketOffers().entrySet().iterator();
            while (it.hasNext()) {
                Map.Entry<BlockPos, ItemMarketOffer> entry = it.next();
                if (entry.getValue().getStockChestPos().equals(pos)) {
                    it.remove();
                    notifyLeader(entry.getValue().getSellerFactionID(), Component.literal("Shop at " + entry.getKey().toShortString() + " removed (chest broken)!").withStyle(ChatFormatting.RED), level);
                }
            }
            for (Map.Entry<String, java.util.List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                if (entry.getValue().contains(pos)) {
                    RecruitsEconomyManager.removeBankChest(entry.getKey(), pos, level);
                    notifyLeader(entry.getKey(), Component.literal("Bank at " + pos.toShortString() + " destroyed!").withStyle(ChatFormatting.RED), level);
                    break;
                }
            }
        }
    }

    private void notifyLeader(String factionID, Component message, ServerLevel level) {
        RecruitsFaction faction = FactionEvents.recruitsFactionManager.getFactionByStringID(factionID);
        if (faction != null && faction.getTeamLeaderUUID() != null) {
            ServerPlayer leader = level.getServer().getPlayerList().getPlayer(faction.getTeamLeaderUUID());
            if (leader != null) leader.sendSystemMessage(message);
        }
    }

    @SubscribeEvent
    public void onPlayerJoin(EntityJoinLevelEvent event) {
        if (event.getLevel().isClientSide() || !(event.getEntity() instanceof ServerPlayer player)) return;
        RecruitsEconomyManager.syncToPlayer(player);
    }

    @SubscribeEvent
    public void onServerTick(TickEvent.ServerTickEvent event) {
        if (event.phase != TickEvent.Phase.END) return;
        if (++tickCounter >= 1000) {
            tickCounter = 0;
            long now = System.currentTimeMillis();
            if (RecruitsEconomyManager.getPendingRequests().entrySet().removeIf(e -> now > e.getValue())) {
                RecruitsEconomyManager.save(event.getServer().overworld());
                RecruitsEconomyManager.syncAll();
            }
        }
    }
}

package com.talhanation.recruits.rrextra;

import net.minecraft.core.BlockPos;
import net.minecraft.nbt.CompoundTag;

public class ItemMarketOffer {
    private String itemID;
    private CompoundTag itemNbt;
    private int price;
    private String currencyID; // Added currency storage
    private String sellerFactionID;
    private BlockPos stockChestPos;

    public ItemMarketOffer(String itemID, CompoundTag itemNbt, int price, String currencyID, String sellerFactionID, BlockPos stockChestPos) {
        this.itemID = itemID;
        this.itemNbt = itemNbt;
        this.price = price;
        this.currencyID = currencyID;
        this.sellerFactionID = sellerFactionID;
        this.stockChestPos = stockChestPos;
    }

    public String getItemID() {
        return itemID;
    }

    public CompoundTag getItemNbt() {
        return itemNbt;
    }

    public int getPrice() {
        return price;
    }

    public String getCurrencyID() {
        return currencyID;
    }

    public String getSellerFactionID() {
        return sellerFactionID;
    }

    public BlockPos getStockChestPos() {
        return stockChestPos;
    }

    public CompoundTag toNBT() {
        CompoundTag nbt = new CompoundTag();
        nbt.putString("ItemID", itemID);
        if (itemNbt != null) {
            nbt.put("ItemNbt", itemNbt);
        }
        nbt.putInt("Price", price);
        nbt.putString("CurrencyID", currencyID);
        nbt.putString("SellerFactionID", sellerFactionID);
        nbt.putLong("StockChestPos", stockChestPos.asLong());
        return nbt;
    }

    public static ItemMarketOffer fromNBT(CompoundTag nbt) {
        return new ItemMarketOffer(
                nbt.getString("ItemID"),
                nbt.contains("ItemNbt") ? nbt.getCompound("ItemNbt") : null,
                nbt.getInt("Price"),
                nbt.contains("CurrencyID") ? nbt.getString("CurrencyID") : "minecraft:emerald",
                nbt.getString("SellerFactionID"),
                BlockPos.of(nbt.getLong("StockChestPos"))
        );
    }
}

package com.talhanation.recruits.rrextra.network;

import com.talhanation.recruits.Main;
import com.talhanation.recruits.rrextra.RecruitsEconomyManager;
import de.maxhenkel.corelib.net.Message;
import net.minecraft.ChatFormatting;
import net.minecraft.core.BlockPos;
import net.minecraft.nbt.CompoundTag;
import net.minecraft.network.chat.Component;
import net.minecraft.resources.ResourceLocation;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.item.ItemStack;
import net.minecraft.world.item.Items;
import net.minecraft.world.scores.Team;
import net.minecraftforge.api.distmarker.Dist;
import net.minecraftforge.network.NetworkEvent;
import net.minecraftforge.registries.ForgeRegistries;

import java.util.List;
import java.util.Objects;

public class MessageRequestSign implements Message<MessageRequestSign> {
    private String itemID;
    private int price;
    private String currencyID;

    public MessageRequestSign() {
    }

    public MessageRequestSign(String itemID, int price, String currencyID) {
        this.itemID = itemID;
        this.price = price;
        this.currencyID = currencyID;
    }

    @Override
    public Dist getExecutingSide() {
        return Dist.DEDICATED_SERVER;
    }

    @Override
    public void executeServerSide(NetworkEvent.Context context) {
        context.enqueueWork(() -> {
            ServerPlayer player = Objects.requireNonNull(context.getSender());
            Team team = player.getTeam();
            if (team == null) {
                player.sendSystemMessage(Component.literal("You must be in a faction to list items!").withStyle(ChatFormatting.RED));
                return;
            }

            String factionID = team.getName();
            List<BlockPos> chests = RecruitsEconomyManager.getBankChests().get(factionID);
            if (chests == null || chests.isEmpty()) {
                player.sendSystemMessage(Component.literal("Your faction must have at least one bank chest registered!").withStyle(ChatFormatting.RED));
                return;
            }

            if (!ForgeRegistries.ITEMS.containsKey(new ResourceLocation(itemID))) {
                player.sendSystemMessage(Component.literal("Invalid item ID: " + itemID).withStyle(ChatFormatting.RED));
                return;
            }

            ItemStack signStack = new ItemStack(Items.OAK_SIGN);
            CompoundTag nbt = signStack.getOrCreateTag();

            // Data for the BlockEntity (SignBlockEntity)
            CompoundTag beTag = new CompoundTag();
            beTag.putString("MarketItem", itemID);
            beTag.putInt("MarketPrice", price);
            beTag.putString("CurrencyID", currencyID);
            nbt.put("BlockEntityTag", beTag);

            // Data for the Item itself (for tooltips/logic)
            nbt.putString("MarketItem", itemID);
            nbt.putInt("MarketPrice", price);
            nbt.putString("CurrencyID", currencyID);

            // Add display name to help identify it
            signStack.setHoverName(Component.literal("Market Listing Sign")
                    .withStyle(ChatFormatting.GOLD)
                    .append(Component.literal(" (Right-click a chest)").withStyle(ChatFormatting.GRAY).withStyle(ChatFormatting.ITALIC)));

            if (!player.getInventory().add(signStack)) {
                player.drop(signStack, false);
            }

            player.sendSystemMessage(Component.literal("Received listing sign for " + itemID + " at " + price + " " + currencyID.replace("minecraft:", "") + ".").withStyle(ChatFormatting.GREEN));
        });
    }

    @Override
    public MessageRequestSign fromBytes(net.minecraft.network.FriendlyByteBuf buf) {
        this.itemID = buf.readUtf();
        this.price = buf.readInt();
        this.currencyID = buf.readUtf();
        return this;
    }

    @Override
    public void toBytes(net.minecraft.network.FriendlyByteBuf buf) {
        buf.writeUtf(itemID);
        buf.writeInt(price);
        buf.writeUtf(currencyID);
    }
}

package com.talhanation.recruits.rrextra.client.gui;

import com.talhanation.recruits.Main;
import com.talhanation.recruits.client.gui.widgets.ListScreenEntryBase;
import com.talhanation.recruits.client.gui.widgets.ListScreenListBase;
import com.talhanation.recruits.rrextra.network.MessageRequestSign;
import net.minecraft.client.Minecraft;
import net.minecraft.client.gui.GuiGraphics;
import net.minecraft.client.gui.components.Button;
import net.minecraft.client.gui.components.EditBox;
import net.minecraft.client.gui.narration.NarrationElementOutput;
import net.minecraft.client.gui.screens.Screen;
import net.minecraft.network.chat.Component;
import net.minecraft.resources.ResourceLocation;
import net.minecraft.world.item.Item;
import net.minecraft.world.item.ItemStack;
import net.minecraft.world.item.Items;
import net.minecraftforge.api.distmarker.Dist;
import net.minecraftforge.api.distmarker.OnlyIn;
import net.minecraftforge.registries.ForgeRegistries;

import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

@OnlyIn(Dist.CLIENT)
public class ItemSelectorScreen extends Screen {
    private ItemList itemList;
    private EditBox searchBox;
    private EditBox priceBox;
    private Item selectedItem;
    private Button confirmButton;
    private String selectedCurrency = "minecraft:emerald";

    public ItemSelectorScreen() {
        super(Component.literal("Item Selector"));
    }

    @Override
    protected void init() {
        super.init();

        this.searchBox = new EditBox(this.font, this.width / 2 - 100, 35, 200, 20, Component.literal("Search..."));
        this.searchBox.setResponder(text -> updateList());
        this.addRenderableWidget(this.searchBox);

        this.itemList = new ItemList(this.width, this.height, 60, this.height - 80, 24);
        this.addWidget(this.itemList);

        this.priceBox = new EditBox(this.font, this.width / 2 - 100, this.height - 70, 60, 20, Component.literal("Price"));
        this.priceBox.setVisible(false);
        this.addRenderableWidget(this.priceBox);

        // Currency selection buttons
        int currX = this.width / 2 - 30;
        int currY = this.height - 70;

        this.addRenderableWidget(Button.builder(Component.literal("E"), b -> selectedCurrency = "minecraft:emerald")
                .bounds(currX, currY, 20, 20).build()).visible = false;
        this.addRenderableWidget(Button.builder(Component.literal("D"), b -> selectedCurrency = "minecraft:diamond")
                .bounds(currX + 22, currY, 20, 20).build()).visible = false;
        this.addRenderableWidget(Button.builder(Component.literal("G"), b -> selectedCurrency = "minecraft:gold_ingot")
                .bounds(currX + 44, currY, 20, 20).build()).visible = false;
        this.addRenderableWidget(Button.builder(Component.literal("I"), b -> selectedCurrency = "minecraft:iron_ingot")
                .bounds(currX + 66, currY, 20, 20).build()).visible = false;

        this.confirmButton = Button.builder(Component.literal("Confirm Listing"), button -> confirmListing())
                .bounds(this.width / 2 + 10, this.height - 45, 100, 20)
                .build();
        this.confirmButton.visible = false;
        this.addRenderableWidget(this.confirmButton);

        this.addRenderableWidget(Button.builder(Component.literal("Back"), button -> this.onClose())
                .bounds(this.width / 2 - 110, this.height - 45, 100, 20)
                .build());

        updateList();
    }

    private void updateList() {
        String query = searchBox.getValue().toLowerCase();
        List<Item> filtered = ForgeRegistries.ITEMS.getValues().stream()
                .filter(item -> item.getDescription().getString().toLowerCase().contains(query))
                .collect(Collectors.toList());

        this.itemList.clearEntries();
        int itemsPerRow = 8;
        for (int i = 0; i < filtered.size(); i += itemsPerRow) {
            int end = Math.min(i + itemsPerRow, filtered.size());
            this.itemList.addEntry(new ItemEntry(this.itemList, filtered.subList(i, end), this));
        }
    }

    public void selectItem(Item item) {
        this.selectedItem = item;
        this.priceBox.setVisible(true);
        this.confirmButton.visible = true;
        this.priceBox.setFocused(true);
        this.children().forEach(c -> {
            if (c instanceof Button b && (b.getMessage().getString().length() == 1 || b.getMessage().getString().contains("Confirm"))) {
                b.visible = true;
            }
        });
    }

    private void confirmListing() {
        if (selectedItem != null) {
            try {
                int price = Integer.parseInt(priceBox.getValue());
                if (price > 0) {
                    ResourceLocation id = ForgeRegistries.ITEMS.getKey(selectedItem);
                    if (id != null) {
                        Main.SIMPLE_CHANNEL.sendToServer(new MessageRequestSign(id.toString(), price, selectedCurrency));
                        this.onClose();
                    }
                }
            } catch (NumberFormatException ignored) {
            }
        }
    }

    @Override
    public void render(GuiGraphics guiGraphics, int mouseX, int mouseY, float partialTick) {
        this.renderBackground(guiGraphics);
        this.itemList.render(guiGraphics, mouseX, mouseY, partialTick);
        guiGraphics.drawCenteredString(this.font, this.title, this.width / 2, 10, 16777215);

        if (selectedItem != null) {
            guiGraphics.drawString(this.font, "Selling: " + selectedItem.getDescription().getString(), this.width / 2 - 100, this.height - 90, 0xAAAAAA);
            guiGraphics.drawString(this.font, "Currency: " + selectedCurrency.replace("minecraft:", ""), this.width / 2 - 100, this.height - 30, 0x55FF55);
        }

        super.render(guiGraphics, mouseX, mouseY, partialTick);
    }

    @Override
    public boolean isPauseScreen() {
        return false;
    }

    @OnlyIn(Dist.CLIENT)
    public static class ItemList extends ListScreenListBase<ItemEntry> {
        public ItemList(int width, int height, int top, int bottom, int itemHeight) {
            super(width, height, top, bottom, itemHeight);
        }

        @Override
        public int addEntry(ItemEntry entry) {
            return super.addEntry(entry);
        }

        @Override
        public void updateNarration(NarrationElementOutput output) {
        }

        public void clearEntries() {
            super.clearEntries();
        }
    }

    @OnlyIn(Dist.CLIENT)
    public static class ItemEntry extends ListScreenEntryBase<ItemEntry> {
        private final List<Item> items;
        private final ItemSelectorScreen parent;
        private final ItemList list;
        private int lastTop;
        private int lastLeft;

        public ItemEntry(ItemList list, List<Item> items, ItemSelectorScreen parent) {
            this.list = list;
            this.items = items;
            this.parent = parent;
        }

        @Override
        public void render(GuiGraphics guiGraphics, int index, int top, int left, int width, int height, int mouseX, int mouseY, boolean isMouseOver, float partialTick) {
            this.lastTop = top;
            this.lastLeft = left;
            for (int i = 0; i < items.size(); i++) {
                Item item = items.get(i);
                int x = left + 5 + i * 22;
                int y = top + 2;

                guiGraphics.renderItem(new ItemStack(item), x, y);

                if (mouseX >= x && mouseX < x + 16 && mouseY >= y && mouseY < y + 16) {
                    guiGraphics.renderTooltip(Minecraft.getInstance().font, new ItemStack(item), mouseX, mouseY);
                }
            }
        }

        @Override
        public boolean mouseClicked(double mouseX, double mouseY, int button) {
            if (button == 0) {
                for (int i = 0; i < items.size(); i++) {
                    int x = lastLeft + 5 + i * 22;
                    int y = lastTop + 2;
                    if (mouseX >= x && mouseX < x + 16 && mouseY >= y && mouseY < y + 16) {
                        parent.selectItem(items.get(i));
                        return true;
                    }
                }
            }
            return super.mouseClicked(mouseX, mouseY, button);
        }

        @Override
        public ListScreenListBase<ItemEntry> getList() {
            return list;
        }
    }
}

