@OnlyIn(Dist.CLIENT)
public class EcoBuyScreen extends Screen {
    private static final ResourceLocation TEXTURE = new ResourceLocation(Main.MOD_ID, "textures/gui/gui_big.png");
    private final String factionID;
    private ShopList list;

    public EcoBuyScreen(String factionID) {
        super(Component.literal("Shop: " + factionID));
        this.factionID = factionID;
    }

    @Override
    protected void init() {
        super.init();
        int x = (this.width - 195) / 2;
        int y = (this.height - 160) / 2;

        this.list = new ShopList(this.minecraft, 175, 120, y + 25, y + 145, 36);
        this.list.setLeftPos(x + 10);
        this.addRenderableWidget(this.list);

        this.addRenderableWidget(new ExtendedButton(x + 10, y + 145, 175, 20, Component.literal("Back"), button -> {
            this.onClose();
        }));
    }

    @Override
    public void render(GuiGraphics guiGraphics, int mouseX, int mouseY, float partialTick) {
        this.renderBackground(guiGraphics);

        int x = (this.width - 195) / 2;
        int y = (this.height - 160) / 2;

        RenderSystem.setShader(GameRenderer::getPositionTexShader);
        RenderSystem.setShaderColor(1F, 1F, 1F, 1F);
        RenderSystem.setShaderTexture(0, TEXTURE);
        guiGraphics.blit(TEXTURE, x, y, 0, 0, 195, 160);

        guiGraphics.drawString(this.font, this.title, x + 195 / 2 - this.font.width(this.title) / 2, y + 10, 4210752, false);

        super.render(guiGraphics, mouseX, mouseY, partialTick);
    }

    @Override
    public boolean isPauseScreen() {
        return false;
    }

    @OnlyIn(Dist.CLIENT)
    class ShopList extends ObjectSelectionList<ShopEntry> {
        public ShopList(Minecraft minecraft, int width, int height, int top, int bottom, int itemHeight) {
            super(minecraft, width, height, top, bottom, itemHeight);

            List<BlockPos> positions = EconomyClientManager.getShoppingSignPositions();
            List<ItemMarketOffer> offers = EconomyClientManager.getShoppingOffers();
            List<Integer> stocks = EconomyClientManager.getShoppingStocks();

            for (int i = 0; i < offers.size(); i++) {
                this.addEntry(new ShopEntry(positions.get(i), offers.get(i), stocks.get(i)));
            }
        }

        @Override
        public void updateNarration(NarrationElementOutput output) {
        }

        @Override
        public int addEntry(ShopEntry entry) {
            return super.addEntry(entry);
        }

        @Override
        public int getRowWidth() {
            return this.width;
        }

        @Override
        protected int getScrollbarPosition() {
            return this.getLeft() + this.width - 6;
        }
    }

    @OnlyIn(Dist.CLIENT)
    class ShopEntry extends ObjectSelectionList.Entry<ShopEntry> {
        private final BlockPos signPos;
        private final ItemMarketOffer offer;
        private final int stock;
        private final ItemStack itemStack;
        private final ItemStack currencyStack;

        public ShopEntry(BlockPos signPos, ItemMarketOffer offer, int stock) {
            this.signPos = signPos;
            this.offer = offer;
            this.stock = stock;
            ResourceLocation itemLoc = ResourceLocation.tryParse(offer.getItemID());
            this.itemStack = itemLoc != null ? new ItemStack(ForgeRegistries.ITEMS.getValue(itemLoc)) : ItemStack.EMPTY;
            ResourceLocation currLoc = ResourceLocation.tryParse(offer.getCurrencyID());
            this.currencyStack = currLoc != null ? new ItemStack(ForgeRegistries.ITEMS.getValue(currLoc)) : ItemStack.EMPTY;
        }

        @Override
        public void render(GuiGraphics guiGraphics, int index, int top, int left, int width, int height, int mouseX, int mouseY, boolean isMouseOver, float partialTick) {
            guiGraphics.renderItem(itemStack, left + 5, top + 5);
            guiGraphics.drawString(Minecraft.getInstance().font, itemStack.getHoverName().getString(), left + 25, top + 5, 16777215);
            guiGraphics.drawString(Minecraft.getInstance().font, "Stock: " + stock, left + 25, top + 15, 11184810);

            // Render currency icon and price
            guiGraphics.renderItem(currencyStack, left + width - 85, top + 15);
            guiGraphics.drawString(Minecraft.getInstance().font, "x" + offer.getPrice(), left + width - 65, top + 20, 16777215);
        }

        @Override
        public boolean mouseClicked(double mouseX, double mouseY, int button) {
            if (button == 0) {
                Minecraft.getInstance().setScreen(new ConfirmPurchaseScreen(signPos, offer, stock, EcoBuyScreen.this));
                return true;
            }
            return super.mouseClicked(mouseX, mouseY, button);
        }

        @Override
        public Component getNarration() {
            return itemStack.getHoverName();
        }
    }

    @OnlyIn(Dist.CLIENT)
    class ConfirmPurchaseScreen extends Screen {
        private final BlockPos signPos;
        private final ItemMarketOffer offer;
        private final int stock;
        private final Screen parent;
        private final String currencyName;

        public ConfirmPurchaseScreen(BlockPos signPos, ItemMarketOffer offer, int stock, Screen parent) {
            super(Component.literal("Confirm Purchase"));
            this.signPos = signPos;
            this.offer = offer;
            this.stock = stock;
            this.parent = parent;
            ResourceLocation currLoc = ResourceLocation.tryParse(offer.getCurrencyID());
            this.currencyName = currLoc != null ? new ItemStack(ForgeRegistries.ITEMS.getValue(currLoc)).getHoverName().getString() : "Currency";
        }

        @Override
        protected void init() {
            super.init();
            int x = this.width / 2;
            int y = this.height / 2;

            this.addRenderableWidget(new ExtendedButton(x - 100, y - 30, 200, 20, Component.literal("Buy x1 (" + offer.getPrice() + " " + currencyName + ")"), b -> buy(1)));
            this.addRenderableWidget(new ExtendedButton(x - 100, y - 5, 200, 20, Component.literal("Buy x10 (" + (offer.getPrice() * 10) + " " + currencyName + ")"), b -> buy(10)));
            this.addRenderableWidget(new ExtendedButton(x - 100, y + 20, 200, 20, Component.literal("Buy x64 (" + (offer.getPrice() * 64) + " " + currencyName + ")"), b -> buy(64)));
            this.addRenderableWidget(new ExtendedButton(x - 100, y + 55, 200, 20, Component.literal("Cancel"), b -> Minecraft.getInstance().setScreen(parent)));
        }

        private void buy(int qty) {
            if (stock < qty) {
                Minecraft.getInstance().player.sendSystemMessage(Component.literal("Not enough stock!").withStyle(net.minecraft.ChatFormatting.RED));
                return;
            }
            Main.SIMPLE_CHANNEL.sendToServer(new MessageBuyMarketItem(signPos, qty));
            this.onClose();
        }

        @Override
        public void render(GuiGraphics guiGraphics, int mouseX, int mouseY, float partialTick) {
            this.renderBackground(guiGraphics);
            super.render(guiGraphics, mouseX, mouseY, partialTick);
            guiGraphics.drawCenteredString(this.font, this.title, this.width / 2, this.height / 2 - 60, 16777215);
        }
    }
}

