        // -------------------------------------------------------------------------
        // FPS
        // -------------------------------------------------------------------------

        private long lastFpsTime = 0;
        private int fpsCounter = 0;
        private int currentFps = 0;

        private void renderFPS(GuiGraphics guiGraphics){
            long currentTime = System.currentTimeMillis();
            fpsCounter++;
            if (currentTime - lastFpsTime >= 1000) {
                currentFps = fpsCounter;
                fpsCounter = 0;
                lastFpsTime = currentTime;
            }
            String fpsText = String.format("FPS: %d", currentFps);
            guiGraphics.drawString(font, fpsText, width - font.width(fpsText) - 15, 5, 0x00FF00);
        }

        // -------------------------------------------------------------------------
        // Faction / claim helpers (unchanged)
        // -------------------------------------------------------------------------

        public boolean isPlayerFactionLeader() {
            return this.isPlayerFactionLeader(ownFaction);
        }

        public boolean isPlayerFactionLeader(RecruitsFaction faction){
            if (player == null || faction == null) return false;
            return faction.getTeamLeaderUUID().equals(player.getUUID());
        }

        public boolean isPlayerClaimLeader() {
            return this.isPlayerClaimLeader(selectedClaim);
        }

        public boolean isPlayerClaimLeader(RecruitsClaim claim){
            if (player == null || claim == null) return false;
            return claim.getPlayerInfo().getUUID().equals(player.getUUID());
        }

        public List<ChunkPos> getClaimArea(ChunkPos pos){
            List<ChunkPos> area = new ArrayList<>();
            if (pos == null) return area;
            int range = 2;
            for (int dx = -range; dx <= range; dx++)
                for (int dz = -range; dz <= range; dz++)
                    area.add(new ChunkPos(pos.x + dx, pos.z + dz));
            return area;
        }

        public void claimArea() {
            if (!canPlayerPay(getClaimCost(ownFaction), player)) return;
            if (!ClientManager.configValueIsClaimingAllowed) return;
            if (!isPlayerInOverworld()) return;

            List<ChunkPos> area = getClaimArea(this.selectedChunk);
            RecruitsClaim newClaim = new RecruitsClaim(ownFaction);

            for (ChunkPos pos : area) newClaim.addChunk(pos);
            newClaim.setCenter(selectedChunk);
            newClaim.setPlayer(new RecruitsPlayerInfo(player.getUUID(), player.getName().getString(), ownFaction));
            Main.SIMPLE_CHANNEL.sendToServer(new MessageDoPayment(player.getUUID(), getClaimCost(ownFaction)));
            ClientManager.recruitsClaims.add(newClaim);
            Main.SIMPLE_CHANNEL.sendToServer(new MessageUpdateClaim(newClaim));
        }

        public void claimChunk() {
            if (!canPlayerPay(ClientManager.configValueChunkCost, player)) return;
            if (!ClientManager.configValueIsClaimingAllowed) return;
            if (!isPlayerInOverworld()) return;
            RecruitsClaim neighborClaim = getNeighborClaim(selectedChunk);
            if (neighborClaim == null) return;
            if (!Objects.equals(ownFaction.getStringID(), neighborClaim.getOwnerFaction().getStringID())) return;
            for (RecruitsClaim claim : ClientManager.recruitsClaims) {
                if (claim.equals(neighborClaim)) {
                    neighborClaim.addChunk(selectedChunk);
                    recalculateCenter(neighborClaim);
                    break;
                }
            }
            Main.SIMPLE_CHANNEL.sendToServer(new MessageDoPayment(player.getUUID(), ClientManager.configValueChunkCost));
            Main.SIMPLE_CHANNEL.sendToServer(new MessageUpdateClaim(neighborClaim));
        }

        @Nullable
        public RecruitsClaim getNeighborClaim(ChunkPos chunk){
            ChunkPos[] neighbors = {
                    new ChunkPos(chunk.x + 1, chunk.z), new ChunkPos(chunk.x - 1, chunk.z),
                    new ChunkPos(chunk.x, chunk.z + 1), new ChunkPos(chunk.x, chunk.z - 1)
            };
            for (ChunkPos neighbor : neighbors)
                for (RecruitsClaim claim : ClientManager.recruitsClaims)
                    if (claim.containsChunk(neighbor)) return claim;
            return null;
        }

        public void recalculateCenter(RecruitsClaim claim){
            List<ChunkPos> chunks = claim.getClaimedChunks();
            if (chunks.isEmpty()) return;
            int minX = Integer.MAX_VALUE, maxX = Integer.MIN_VALUE;
            int minZ = Integer.MAX_VALUE, maxZ = Integer.MIN_VALUE;
            for (ChunkPos pos : chunks) {
                if (pos.x < minX) minX = pos.x;
                if (pos.x > maxX) maxX = pos.x;
                if (pos.z < minZ) minZ = pos.z;
                if (pos.z > maxZ) maxZ = pos.z;
            }
            claim.setCenter(new ChunkPos((minX + maxX) / 2, (minZ + maxZ) / 2));
        }

        public void centerOnClaim(RecruitsClaim claim){
            if (claim == null || claim.getCenter() == null) return;
            ChunkPos center = claim.getCenter();
            offsetX = -(center.x * 16 * scale) + width / 2.0;
            offsetZ = -(center.z * 16 * scale) + height / 2.0;
        }

        public Rectangle getClaimScreenBounds(RecruitsClaim claim){
            int minX = Integer.MAX_VALUE, maxX = Integer.MIN_VALUE;
            int minZ = Integer.MAX_VALUE, maxZ = Integer.MIN_VALUE;
            for (ChunkPos pos : claim.getClaimedChunks()) {
                minX = Math.min(minX, pos.x);
                maxX = Math.max(maxX, pos.x);
                minZ = Math.min(minZ, pos.z);
                maxZ = Math.max(maxZ, pos.z);
            }
            int x1 = (int) (offsetX + minX * 16 * scale);
            int y1 = (int) (offsetZ + minZ * 16 * scale);
            int x2 = (int) (offsetX + (maxX + 1) * 16 * scale);
            int y2 = (int) (offsetZ + (maxZ + 1) * 16 * scale);
            return new Rectangle(x1, y1, x2 - x1, y2 - y1);
        }

        public Point getClaimInfoMenuPosition(RecruitsClaim claim,int menuWidth, int menuHeight){
            Rectangle bounds = getClaimScreenBounds(claim);
            int margin = 10;
            int x = bounds.x + bounds.width + margin;
            int y = bounds.y + bounds.height / 2 - menuHeight / 2;
            if (x + menuWidth > width) x = bounds.x - menuWidth - margin;
            if (y < 10) y = 10;
            if (y + menuHeight > height - 10) y = height - menuHeight - 10;
            return new Point(x, y);
        }

        public boolean canRemoveChunk(ChunkPos pos, RecruitsClaim claim){
            if (pos == null || ownFaction == null) return false;
            if (isPlayerTooFar(pos)) return false;
            List<ChunkPos> claimedChunks = claim.getClaimedChunks();
            if (!claimedChunks.contains(pos)) return false;
            int unclaimedNeighbors = 0;
            for (ChunkPos n : new ChunkPos[]{
                    new ChunkPos(pos.x + 1, pos.z), new ChunkPos(pos.x - 1, pos.z),
                    new ChunkPos(pos.x, pos.z + 1), new ChunkPos(pos.x, pos.z - 1)}) {
                if (!claimedChunks.contains(n)) unclaimedNeighbors++;
            }
            return unclaimedNeighbors >= 2;
        }

        private boolean isPlayerTooFar(ChunkPos pos){
            if (pos == null) return true;
            int diffX = Math.abs(player.chunkPosition().x) - Math.abs(pos.x);
            int diffZ = Math.abs(player.chunkPosition().z) - Math.abs(pos.z);
            return Math.abs(diffZ) > 4 || Math.abs(diffX) > 4;
        }

        public int getClaimCost(RecruitsFaction ownerTeam){
            if (!ClientManager.configValueCascadeClaimCost) return ClientManager.configValueClaimCost;
            int amount = 1;
            if (ownerTeam != null)
                for (RecruitsClaim claim : ClientManager.recruitsClaims)
                    if (claim.getOwnerFaction().getStringID().equals(ownerTeam.getStringID())) amount++;
            return amount * ClientManager.configValueClaimCost;
        }

        public boolean canPlayerPay( int cost, Player player){
            return player.isCreative() || cost <= player.getInventory().countItem(ClientManager.currencyItemStack.getItem());
        }

        public static boolean isInBufferZone(ChunkPos chunk, RecruitsFaction ownFaction){
            if (ownFaction == null) return false;
            for (RecruitsClaim claim : ClientManager.recruitsClaims) {
                if (claim.getOwnerFaction() == null || claim.getOwnerFaction().getStringID().equals(ownFaction.getStringID()))
                    continue;
                for (ChunkPos claimChunk : claim.getClaimedChunks()) {
                    int dx = Math.abs(chunk.x - claimChunk.x);
                    int dz = Math.abs(chunk.z - claimChunk.z);
                    if (dx <= 3 && dz <= 3 && !(dx == 0 && dz == 0)) return true;
                }
            }
            return false;
        }

        private boolean isPlayerInOverworld () {
            return minecraft.level != null && minecraft.level.dimension() == net.minecraft.world.level.Level.OVERWORLD;
        }

        public boolean canClaimChunk(ChunkPos pos){
            if (!ClientManager.configValueIsClaimingAllowed || pos == null || ClientManager.ownFaction == null)
                return false;
            if (isPlayerTooFar(pos)) return false;
            for (RecruitsClaim c : ClientManager.recruitsClaims) if (c.containsChunk(pos)) return false;
            RecruitsClaim neighbor = getNeighborClaim(pos);
            if (neighbor == null || neighbor.getClaimedChunks().size() >= RecruitsClaim.MAX_SIZE) return false;
            return !isInBufferZone(pos, ClientManager.ownFaction);
        }

        public boolean canClaimArea(List < ChunkPos > areaChunks) {
            if (selectedChunk == null || areaChunks == null || areaChunks.isEmpty() || ClientManager.ownFaction == null)
                return false;
            if (isPlayerTooFar(selectedChunk)) return false;
            for (ChunkPos chunk : areaChunks) {
                for (RecruitsClaim c : ClientManager.recruitsClaims) if (c.containsChunk(chunk)) return false;
                if (isInBufferZone(chunk, ClientManager.ownFaction)) return false;
            }
            return true;
        }

        public List<ChunkPos> getClaimableChunks(ChunkPos center,int radius){
            List<ChunkPos> result = new ArrayList<>();
            if (center == null || ClientManager.ownFaction == null) return result;
            for (int x = center.x - radius; x <= center.x + radius; x++)
                for (int z = center.z - radius; z <= center.z + radius; z++) {
                    ChunkPos chunk = new ChunkPos(x, z);
                    if (canClaimChunkRaw(chunk)) result.add(chunk);
                }
            return result;
        }

        public boolean canClaimChunkRaw(ChunkPos pos){
            for (RecruitsClaim c : ClientManager.recruitsClaims) if (c.containsChunk(pos)) return false;
            RecruitsClaim neighbor = getNeighborClaim(pos);
            if (neighbor == null) return false;
            return !isInBufferZone(pos, ClientManager.ownFaction);
        }
    }

package com.talhanation.recruits.client.gui.worldmap;

import com.talhanation.recruits.Main;
import com.talhanation.recruits.client.ClientManager;
import com.talhanation.recruits.client.gui.diplomacy.DiplomacyEditScreen;
import com.talhanation.recruits.network.MessageTeleportPlayer;
import com.talhanation.recruits.network.MessageUpdateClaim;
import net.minecraft.client.Minecraft;
import net.minecraft.client.gui.GuiGraphics;
import net.minecraft.network.chat.Component;
import net.minecraft.world.item.ItemStack;

import java.util.ArrayList;
import java.util.List;
import java.util.function.BooleanSupplier;
import java.util.function.Consumer;

public class WorldMapContextMenu {

    private static final Component TEXT_DIPLOMACY          = Component.translatable("gui.recruits.map.diplomacy");
    private static final Component TEXT_CLAIM_CHUNK        = Component.translatable("gui.recruits.map.claim_chunk");
    private static final Component TEXT_CLAIM_AREA         = Component.translatable("gui.recruits.map.claim_area");
    private static final Component TEXT_EDIT_CLAIM         = Component.translatable("gui.recruits.map.edit_claim");
    private static final Component TEXT_REMOVE_CHUNK       = Component.translatable("gui.recruits.map.remove_chunk");
    private static final Component TEXT_CENTER_MAP         = Component.translatable("gui.recruits.map.center_map");
    private static final Component TEXT_REMOVE_CHUNK_ADMIN = Component.translatable("gui.recruits.map.remove_chunk_admin");
    private static final Component TEXT_DELETE_CLAIM_ADMIN = Component.translatable("gui.recruits.map.delete_claim_admin");
    private static final Component TEXT_TELEPORT_ADMIN     = Component.translatable("gui.recruits.map.teleport_admin");

    private final List<ContextMenuEntry> entries = new ArrayList<>();
    private int x, y;
    private boolean visible = false;
    private final int width = 150;
    private final int entryHeight = 20;
    private final WorldMapScreen worldMapScreen;

    /** Snapshot of mouse position taken when the menu was opened. Used for waypoint hit-detection. */
    private double snapshotMouseX;
    private double snapshotMouseY;

    public WorldMapContextMenu(WorldMapScreen worldMapScreen) {
        this.worldMapScreen = worldMapScreen;
        ItemStack itemStackClaimChunk = new ItemStack(ClientManager.currencyItemStack.getItem());
        itemStackClaimChunk.setCount(ClientManager.configValueChunkCost);
        ItemStack itemStackClaimArea = new ItemStack(ClientManager.currencyItemStack.getItem());
        itemStackClaimArea.setCount(worldMapScreen.getClaimCost(ClientManager.ownFaction));

        addEntry(TEXT_DIPLOMACY.getString(),
                () -> ClientManager.ownFaction != null
                        && this.worldMapScreen.selectedClaim != null
                        && this.worldMapScreen.selectedClaim.getOwnerFaction() != null
                        && !ClientManager.ownFaction.getStringID().equals(this.worldMapScreen.selectedClaim.getOwnerFactionStringID()),
                (screen) -> Minecraft.getInstance().setScreen(new DiplomacyEditScreen(screen, screen.selectedClaim.getOwnerFaction()))
        );

        addEntry(TEXT_CLAIM_CHUNK.getString(),
                () -> this.worldMapScreen.canClaimChunk(worldMapScreen.selectedChunk)
                        && (this.worldMapScreen.isPlayerFactionLeader()
                        || this.worldMapScreen.isPlayerClaimLeader(worldMapScreen.getNeighborClaim(worldMapScreen.selectedChunk))),
                WorldMapScreen::claimChunk,
                itemStackClaimChunk,
                "bufferzone, chunk"
        );

        addEntry(TEXT_CLAIM_AREA.getString(),
                () -> this.worldMapScreen.canClaimArea(worldMapScreen.getClaimArea(worldMapScreen.selectedChunk))
                        && this.worldMapScreen.isPlayerFactionLeader(),
                WorldMapScreen::claimArea,
                itemStackClaimArea,
                "bufferzone, area"
        );

        addEntry("Add Waypoint",
                () -> this.worldMapScreen.selectedRoute != null
                        && this.worldMapScreen.canPlaceWaypointAt(
                                this.worldMapScreen.snapshotWorldX,
                                this.worldMapScreen.snapshotWorldZ),
                WorldMapScreen::addWaypointAtClicked
        );

        addEntry("Remove Waypoint",
                () -> this.worldMapScreen.selectedRoute != null
                        && this.worldMapScreen.isWaypointHoveredAt(snapshotMouseX, snapshotMouseY),
                (screen) -> screen.removeWaypointAt(snapshotMouseX, snapshotMouseY)
        );

        addEntry("Edit Waypoint",
                () -> this.worldMapScreen.selectedRoute != null
                        && this.worldMapScreen.isWaypointHoveredAt(snapshotMouseX, snapshotMouseY),
                (screen) -> screen.openWaypointEditPopup(snapshotMouseX, snapshotMouseY)
        );

        addEntry(TEXT_EDIT_CLAIM.getString(),
                () -> this.worldMapScreen.selectedClaim != null
                        && this.worldMapScreen.isPlayerFactionLeader(this.worldMapScreen.selectedClaim.getOwnerFaction())
                        || this.worldMapScreen.isPlayerClaimLeader(),
                (screen) -> {
                    screen.getMinecraft().setScreen(new ClaimEditScreen(screen, screen.selectedClaim, screen.getPlayer()));
                    screen.selectedClaim = null;
                }
        );

        addEntry(TEXT_REMOVE_CHUNK.getString(),
                () -> this.worldMapScreen.selectedChunk != null && this.worldMapScreen.selectedClaim != null
                        && worldMapScreen.canRemoveChunk(worldMapScreen.selectedChunk, worldMapScreen.selectedClaim)
                        && (this.worldMapScreen.isPlayerFactionLeader(worldMapScreen.selectedClaim.getOwnerFaction())
                        || this.worldMapScreen.isPlayerClaimLeader(worldMapScreen.selectedClaim)),
                (screen) -> {
                    if (screen.selectedClaim.containsChunk(screen.selectedChunk)) {
                        screen.selectedClaim.removeChunk(screen.selectedChunk);
                        screen.selectedChunk = null;
                        Main.SIMPLE_CHANNEL.sendToServer(new MessageUpdateClaim(screen.selectedClaim));
                    }
                }
        );

        addEntry(TEXT_CENTER_MAP.getString(), WorldMapScreen::centerOnPlayer);

        addEntry(TEXT_REMOVE_CHUNK_ADMIN.getString(),
                () -> this.worldMapScreen.selectedChunk != null && this.worldMapScreen.selectedClaim != null
                        && this.worldMapScreen.isPlayerAdminAndCreative()
                        && worldMapScreen.canRemoveChunk(worldMapScreen.selectedChunk, worldMapScreen.selectedClaim)
                        && !(this.worldMapScreen.isPlayerFactionLeader(worldMapScreen.selectedClaim.getOwnerFaction())
                        || this.worldMapScreen.isPlayerClaimLeader(worldMapScreen.selectedClaim)),
                (screen) -> {
                    if (screen.selectedClaim.containsChunk(screen.selectedChunk)) {
                        screen.selectedClaim.removeChunk(screen.selectedChunk);
                        screen.selectedChunk = null;
                        Main.SIMPLE_CHANNEL.sendToServer(new MessageUpdateClaim(screen.selectedClaim));
                    }
                },
                "admin"
        );

        addEntry(TEXT_DELETE_CLAIM_ADMIN.getString(),
                () -> this.worldMapScreen.isPlayerAdminAndCreative() && this.worldMapScreen.selectedClaim != null,
                (screen) -> {
                    screen.selectedClaim.isRemoved = true;
                    Main.SIMPLE_CHANNEL.sendToServer(new MessageUpdateClaim(screen.selectedClaim));
                    screen.selectedClaim = null;
                },
                "admin"
        );

        addEntry(TEXT_TELEPORT_ADMIN.getString(),
                worldMapScreen::isPlayerAdminAndCreative,
                (screen) -> Main.SIMPLE_CHANNEL.sendToServer(new MessageTeleportPlayer(screen.getClickedBlockPos())),
                "admin"
        );
    }

    public void addEntry(String text, BooleanSupplier condition, Consumer<WorldMapScreen> action, ItemStack itemStack, String tag) {
        entries.add(new ContextMenuEntry(Component.literal(text), condition, action, itemStack, tag));
    }
    public void addEntry(String text, BooleanSupplier condition, Consumer<WorldMapScreen> action, String tag) {
        entries.add(new ContextMenuEntry(Component.literal(text), condition, action, ItemStack.EMPTY, tag));
    }
    public void addEntry(String text, BooleanSupplier condition, Consumer<WorldMapScreen> action) {
        entries.add(new ContextMenuEntry(Component.literal(text), condition, action, ItemStack.EMPTY, ""));
    }
    public void addEntry(String text, Consumer<WorldMapScreen> action) {
        addEntry(text, () -> true, action);
    }

    public void openAt(int x, int y) {
        this.x = Math.max(10, Math.min(x, worldMapScreen.width - width - 10));
        this.y = Math.max(10, Math.min(y, worldMapScreen.height - entries.size() * entryHeight - 10));
        this.visible = true;
        // Snapshot mouse position at open time
        this.snapshotMouseX = worldMapScreen.mouseX;
        this.snapshotMouseY = worldMapScreen.mouseY;
    }

    public void close() { this.visible = false; }
    public boolean isVisible() { return visible; }

    private String hoveredEntryTag = null;
    public String getHoveredEntryTag() { return hoveredEntryTag; }

    public void render(GuiGraphics guiGraphics, WorldMapScreen screen) {
        if (!visible) return;

        hoveredEntryTag = null;

        int visibleEntries = (int) entries.stream().filter(e -> e.shouldShow(screen)).count();
        int height = visibleEntries * entryHeight;

        guiGraphics.fill(x, y, x + width, y + height, 0xFF1A1A1A);
        guiGraphics.renderOutline(x, y, width, height, 0xFF555555);

        int entryY = y;
        for (ContextMenuEntry entry : entries) {
            if (entry.shouldShow(screen)) {
                boolean hovered = isMouseOverEntry(x, entryY);
                if (hovered) hoveredEntryTag = entry.getTag();

                guiGraphics.fill(x, entryY, x + width, entryY + entryHeight, hovered ? 0xFF333333 : 0xFF1A1A1A);

                int textColor;
                if (entry.getTag().equals("admin")) {
                    textColor = hovered ? 0xFFFF5555 : 0xFFAA4444;
                } else {
                    textColor = hovered ? 0xFFFFFF : 0xCCCCCC;
                }

                guiGraphics.drawString(screen.getMinecraft().font, entry.text(), x + 8, entryY + 6, textColor);

                if (!entry.stack.isEmpty()) {
                    guiGraphics.renderFakeItem(entry.stack, x + width - 20, entryY + 1);
                    guiGraphics.renderItemDecorations(screen.getMinecraft().font, entry.stack, x + width - 20, entryY + 1);
                }

                entryY += entryHeight;
            }
        }
    }

    public boolean mouseClicked(double mouseX, double mouseY, int button, WorldMapScreen screen) {
        if (!visible || button != 0) return false;

        int entryY = y;
        for (ContextMenuEntry entry : entries) {
            if (entry.shouldShow(screen)) {
                if (mouseX >= x && mouseX <= x + width && mouseY >= entryY && mouseY <= entryY + entryHeight) {
                    entry.execute(screen);
                    close();
                    return true;
                }
                entryY += entryHeight;
            }
        }

        close();
        return false;
    }

    private boolean isMouseOverEntry(int entryX, int entryY) {
        double mouseX = this.worldMapScreen.mouseX;
        double mouseY = this.worldMapScreen.mouseY;
        return mouseX >= entryX && mouseX <= entryX + width && mouseY >= entryY && mouseY <= entryY + entryHeight;
    }

    private record ContextMenuEntry(Component text, BooleanSupplier condition, Consumer<WorldMapScreen> action, ItemStack stack, String tag) {
        public String getTag() { return tag; }
        public boolean shouldShow(WorldMapScreen screen) { return condition.getAsBoolean(); }
        public void execute(WorldMapScreen screen) { action.accept(screen); }
    }
}

package com.talhanation.recruits.world;

import com.talhanation.recruits.DiplomacyEvent;
import net.minecraftforge.common.MinecraftForge;

import com.talhanation.recruits.Main;
import com.talhanation.recruits.FactionEvents;
import com.talhanation.recruits.network.MessageToClientSetDiplomaticToast;
import com.talhanation.recruits.network.MessageToClientUpdateDiplomacyList;
import net.minecraft.nbt.CompoundTag;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.entity.player.Player;
import net.minecraftforge.network.PacketDistributor;

import java.util.*;

public class RecruitsDiplomacyManager {
    public Map<String, Map<String, DiplomacyStatus>> diplomacyMap = new HashMap<>();

    public void load(ServerLevel level) {
        RecruitsDiplomacySaveData data = RecruitsDiplomacySaveData.get(level);
        diplomacyMap = data.getDiplomacyMap();
    }

    public void save(ServerLevel level) {
        RecruitsDiplomacySaveData data = RecruitsDiplomacySaveData.get(level);

        for (Map.Entry<String, Map<String, DiplomacyStatus>> entry : diplomacyMap.entrySet()) {
            String team = entry.getKey();
            Map<String, DiplomacyStatus> relations = entry.getValue();

            for (Map.Entry<String, DiplomacyStatus> relationEntry : relations.entrySet()) {
                data.setRelation(team, relationEntry.getKey(), relationEntry.getValue().getByteValue());
            }
        }

        data.setDirty();

        this.broadcastDiplomacyMapToAll(level);
    }

    public void setRelation(String team, String otherTeam, DiplomacyStatus relation, ServerLevel level){
        this.setRelation(team, otherTeam, relation, level, true);
    }
    public void setRelation(String team, String otherTeam, DiplomacyStatus relation, ServerLevel level, boolean notifyPlayers) {
        DiplomacyStatus currentRelation = this.getRelation(team, otherTeam);

        if (currentRelation == relation) {
            return;
        }

        // DiplomacyEvent.RelationChanged feuern – cancelable
        DiplomacyEvent.RelationChanged relEvent =
                new DiplomacyEvent.RelationChanged(team, otherTeam, level, currentRelation, relation);
        if (MinecraftForge.EVENT_BUS.post(relEvent)) return;

        diplomacyMap.computeIfAbsent(team, k -> new HashMap<>()).put(otherTeam, relation);
        if(notifyPlayers) this.notifyPlayersInTeam(team, otherTeam, relation, level);

        this.save(level);
    }

    public DiplomacyStatus getRelation(String team, String otherTeam) {
        return diplomacyMap.getOrDefault(team, new HashMap<>()).getOrDefault(otherTeam, DiplomacyStatus.NEUTRAL);
    }

    public enum DiplomacyStatus {
        NEUTRAL((byte) 0),
        ALLY((byte) 1),
        ENEMY((byte) 2);

        private final byte byteValue;

        DiplomacyStatus(byte byteValue) {
            this.byteValue = byteValue;
        }

        public byte getByteValue() {
            return byteValue;
        }

        public static DiplomacyStatus fromByte(byte value) {
            return switch (value) {
                case 1 -> ALLY;
                case 2 -> ENEMY;
                default -> NEUTRAL;
            };
        }
    }

    public void notifyPlayersInTeam(String teamName, String otherTeamName, DiplomacyStatus relation, ServerLevel level) {
        RecruitsFaction team = FactionEvents.recruitsFactionManager.getFactionByStringID(teamName);
        RecruitsFaction otherTeam = FactionEvents.recruitsFactionManager.getFactionByStringID(otherTeamName);

        if(team != null && otherTeam != null){
            List<ServerPlayer> playersInTeam = FactionEvents.recruitsFactionManager.getPlayersInTeam(team.getStringID(), level);
            for (ServerPlayer player : playersInTeam) {
                Main.SIMPLE_CHANNEL.send(PacketDistributor.PLAYER.with(()-> player), new MessageToClientSetDiplomaticToast(relation.getByteValue(), otherTeam));
