package com.talhanation.recruits.rrextra;

import net.minecraft.server.level.ServerLevel;
import net.minecraft.world.level.ChunkPos;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public class TradeRouteManager {
    private static final Map<ChunkPos, Set<TradeRoute>> routesByChunk = new ConcurrentHashMap<>();
    private static final List<TradeRoute> allRoutes = new ArrayList<>();

    public static synchronized void load(ServerLevel level) {
        TradeRouteSaveData data = TradeRouteSaveData.get(level);
        allRoutes.clear();
        routesByChunk.clear();

        List<TradeRoute> loadedRoutes = data.getRoutes();
        for (TradeRoute route : loadedRoutes) {
            allRoutes.add(route);
            for (ChunkPos pos : route.getPath()) {
                routesByChunk.computeIfAbsent(pos, k -> new HashSet<>()).add(route);
            }
        }
    }

    public static synchronized void save(ServerLevel level) {
        TradeRouteSaveData data = TradeRouteSaveData.get(level);
        data.setRoutes(new ArrayList<>(allRoutes));
    }

    public static synchronized void addRoute(TradeRoute route, ServerLevel level) {
        if (!allRoutes.contains(route)) {
            allRoutes.add(route);
            for (ChunkPos pos : route.getPath()) {
                routesByChunk.computeIfAbsent(pos, k -> new HashSet<>()).add(route);
            }
            save(level);
        }
    }

    public static synchronized void removeRoute(TradeRoute route, ServerLevel level) {
        if (allRoutes.remove(route)) {
            for (ChunkPos pos : route.getPath()) {
                Set<TradeRoute> routes = routesByChunk.get(pos);
                if (routes != null) {
                    routes.remove(route);
                    if (routes.isEmpty()) {
                        routesByChunk.remove(pos);
                    }
                }
            }
            save(level);
        }
    }

    public static synchronized Set<TradeRoute> getRoutesAt(ChunkPos chunkPos) {
        Set<TradeRoute> routes = routesByChunk.get(chunkPos);
        return routes != null ? Collections.unmodifiableSet(new HashSet<>(routes)) : Collections.emptySet();
    }

    public static synchronized List<TradeRoute> getAllRoutes() {
        return Collections.unmodifiableList(new ArrayList<>(allRoutes));
    }

    public static void createTradeRoute(net.minecraft.server.level.ServerPlayer player, java.util.List<net.minecraft.world.level.ChunkPos> path, String targetFactionID) {
        String playerFactionID = player.getTeam().getName();
        int health = 10 + path.size();
        TradeRoute route = new TradeRoute(UUID.randomUUID(), playerFactionID, targetFactionID, path, health, false, 0);
        addRoute(route, player.serverLevel());
        syncAll();
    }

    public static void declareWarOnRoute(net.minecraft.server.level.ServerPlayer player, UUID routeUUID) {
        TradeRoute route = null;
        for (TradeRoute r : allRoutes) {
            if (r.getUuid().equals(routeUUID)) {
                route = r;
                break;
            }
        }

        if (route != null && player.getTeam() != null) {
            String attacker = player.getTeam().getName();
            String factionA = route.getFactionA();
            String factionB = route.getFactionB();
            net.minecraft.server.level.ServerLevel level = player.serverLevel();

            com.talhanation.recruits.world.RecruitsDiplomacyManager.DiplomacyStatus ENEMY = com.talhanation.recruits.world.RecruitsDiplomacyManager.DiplomacyStatus.ENEMY;

            com.talhanation.recruits.FactionEvents.recruitsDiplomacyManager.setRelation(attacker, factionA, ENEMY, level);
            com.talhanation.recruits.FactionEvents.recruitsDiplomacyManager.setRelation(attacker, factionB, ENEMY, level);

            route.setVulnerable(true);
            save(level);
            syncAll();
        }
    }

    public static void initiateDissolution(net.minecraft.server.level.ServerPlayer player, UUID routeUUID) {
        TradeRoute route = null;
        for (TradeRoute r : allRoutes) {
            if (r.getUuid().equals(routeUUID)) {
                route = r;
                break;
            }
        }

        if (route != null) {
            route.setGracePeriodEndTime(System.currentTimeMillis() + 172800000L); // 48 hours
            save(player.serverLevel());
            syncAll();
        }
    }

    public static void initiateDissolution(net.minecraft.server.level.ServerPlayer player, String partnerID) {
        if (player.getTeam() == null) return;
        TradeRoute route = getRouteBetween(player.getTeam().getName(), partnerID);
        if (route != null) {
            initiateDissolution(player, route.getUuid());
        }
    }

    public static void confirmRouteDeletion(net.minecraft.server.level.ServerPlayer player, UUID routeUUID) {
        TradeRoute routeToRemove = null;
        for (TradeRoute route : allRoutes) {
            if (route.getUuid().equals(routeUUID)) {
                routeToRemove = route;
                break;
            }
        }

        if (routeToRemove != null) {
            if (routeToRemove.getGracePeriodEndTime() > 0 && System.currentTimeMillis() >= routeToRemove.getGracePeriodEndTime()) {
                removeRoute(routeToRemove, player.serverLevel());
                syncAll();
            }
        }
    }

    public static void confirmRouteDeletion(net.minecraft.server.level.ServerPlayer player, String partnerID) {
        if (player.getTeam() == null) return;
        TradeRoute route = getRouteBetween(player.getTeam().getName(), partnerID);
        if (route != null) {
            confirmRouteDeletion(player, route.getUuid());
        }
    }

    public static TradeRoute getRouteBetween(String factionA, String factionB) {
        for (TradeRoute route : allRoutes) {
            if ((route.getFactionA().equals(factionA) && route.getFactionB().equals(factionB)) ||
                    (route.getFactionA().equals(factionB) && route.getFactionB().equals(factionA))) {
                return route;
            }
        }
        return null;
    }

    public static void syncAll() {
        com.talhanation.recruits.Main.SIMPLE_CHANNEL.send(net.minecraftforge.network.PacketDistributor.ALL.noArg(), new com.talhanation.recruits.rrextra.network.MessageSyncTradeRoutes(new ArrayList<>(allRoutes)));
    }

    public static void syncToPlayer(net.minecraft.server.level.ServerPlayer player) {
        com.talhanation.recruits.Main.SIMPLE_CHANNEL.send(net.minecraftforge.network.PacketDistributor.PLAYER.with(() -> player), new com.talhanation.recruits.rrextra.network.MessageSyncTradeRoutes(new ArrayList<>(allRoutes)));
    }
}

package com.talhanation.recruits.rrextra.network;

import com.talhanation.recruits.FactionEvents;
import com.talhanation.recruits.rrextra.TradeRouteManager;
import com.talhanation.recruits.world.RecruitsFaction;
import de.maxhenkel.corelib.net.Message;
import net.minecraft.network.FriendlyByteBuf;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.level.ChunkPos;
import net.minecraftforge.api.distmarker.Dist;
import net.minecraftforge.network.NetworkEvent;

import java.util.ArrayList;
import java.util.List;
import java.util.Objects;

public class MessageCreateTradeRoute implements Message<MessageCreateTradeRoute> {
    private List<ChunkPos> path;
    private String targetFactionID;

    public MessageCreateTradeRoute() {}

    public MessageCreateTradeRoute(List<ChunkPos> path, String targetFactionID) {
        this.path = path;
        this.targetFactionID = targetFactionID;
    }

    @Override
    public Dist getExecutingSide() {
        return Dist.DEDICATED_SERVER;
    }

    @Override
    public void executeServerSide(NetworkEvent.Context context) {
        context.enqueueWork(() -> {
            ServerPlayer player = Objects.requireNonNull(context.getSender());
            if (player.getTeam() == null) return;

            RecruitsFaction faction = FactionEvents.recruitsFactionManager.getFactionByStringID(player.getTeam().getName());
            if (faction == null) return;

            if (!faction.getTeamLeaderUUID().equals(player.getUUID())) return;

            TradeRouteManager.createTradeRoute(player, path, targetFactionID);
            TradeRouteManager.syncAll();
        });
    }

    @Override
    public MessageCreateTradeRoute fromBytes(FriendlyByteBuf buf) {
        int size = buf.readInt();
        this.path = new ArrayList<>(size);
        for (int i = 0; i < size; i++) {
            path.add(new ChunkPos(buf.readLong()));
        }
        this.targetFactionID = buf.readUtf();
        return this;
    }

    @Override
    public void toBytes(FriendlyByteBuf buf) {
        buf.writeInt(path.size());
        for (ChunkPos pos : path) {
            buf.writeLong(pos.toLong());
        }
        buf.writeUtf(targetFactionID);
    }
}

