package com.talhanation.recruits.rrextra.network;

import com.talhanation.recruits.rrextra.TradeRoute;
import com.talhanation.recruits.rrextra.client.TradeRouteClientManager;
import de.maxhenkel.corelib.net.Message;
import net.minecraft.network.FriendlyByteBuf;
import net.minecraftforge.api.distmarker.Dist;
import net.minecraftforge.api.distmarker.OnlyIn;
import net.minecraftforge.network.NetworkEvent;

import java.util.ArrayList;
import java.util.List;

public class MessageSyncTradeRoutes implements Message<MessageSyncTradeRoutes> {
    private List<TradeRoute> allRoutes;

    public MessageSyncTradeRoutes() {}

    public MessageSyncTradeRoutes(List<TradeRoute> allRoutes) {
        this.allRoutes = allRoutes;
    }

    @Override
    public Dist getExecutingSide() {
        return Dist.CLIENT;
    }

    @Override
    @OnlyIn(Dist.CLIENT)
    public void executeClientSide(NetworkEvent.Context context) {
        context.enqueueWork(() -> {
            TradeRouteClientManager.setAllRoutes(allRoutes);
        });
    }

    @Override
    public MessageSyncTradeRoutes fromBytes(FriendlyByteBuf buf) {
        int size = buf.readInt();
        this.allRoutes = new ArrayList<>(size);
        for (int i = 0; i < size; i++) {
            allRoutes.add(TradeRoute.fromNBT(buf.readNbt()));
        }
        return this;
    }

    @Override
    public void toBytes(FriendlyByteBuf buf) {
        buf.writeInt(allRoutes.size());
        for (TradeRoute route : allRoutes) {
            buf.writeNbt(route.toNBT());
        }
    }
}

package com.talhanation.recruits.rrextra;

import com.talhanation.recruits.FactionEvents;
