import net.minecraft.network.chat.HoverEvent;
import net.minecraft.network.chat.MutableComponent;
import net.minecraft.resources.ResourceLocation;
import net.minecraft.server.level.ServerLevel;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.item.ItemStack;
import net.minecraft.world.item.SignItem;
import net.minecraft.world.level.ChunkPos;
import net.minecraft.world.level.block.Blocks;
import net.minecraft.world.level.block.WallSignBlock;
import net.minecraft.world.level.block.entity.SignBlockEntity;
import net.minecraft.world.level.block.state.BlockState;
import net.minecraft.world.scores.Team;
import net.minecraftforge.event.TickEvent;
import net.minecraftforge.event.entity.EntityJoinLevelEvent;
import net.minecraftforge.event.entity.player.PlayerInteractEvent;
import net.minecraftforge.event.level.BlockEvent;
import net.minecraftforge.eventbus.api.SubscribeEvent;

import java.util.Iterator;
import java.util.List;
import java.util.Map;

public class EconomyEvents {
    private static int tickCounter = 0;

    // Registers Market Shops instantly when the special sign is placed
    @SubscribeEvent
    public void onSignPlaced(BlockEvent.EntityPlaceEvent event) {
        if (event.getLevel().isClientSide() || !(event.getEntity() instanceof ServerPlayer player)) return;

        BlockPos pos = event.getPos();
        ServerLevel level = player.serverLevel();
        BlockState state = event.getPlacedBlock();

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            ItemStack held = player.getMainHandItem();
            if (!(held.getItem() instanceof SignItem)) held = player.getOffhandItem();

            if (held.getItem() instanceof SignItem && held.hasTag()) {
                CompoundTag tag = held.getTag();
                if (tag.contains("MarketItem")) {
                    SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
                    if (sign != null) {
                        registerMarketShop(player, level, pos, state, sign, tag);
                    }
                }
            }
        }
    }

    // Handles interaction: 
    // 1. Right-click PAPEL sign to activate bank.
    // 2. Right-click Market sign to open the buy menu.
    @SubscribeEvent
    public void onSignInteract(PlayerInteractEvent.RightClickBlock event) {
        if (event.getLevel().isClientSide() || event.getHand() != InteractionHand.MAIN_HAND || !(event.getEntity() instanceof ServerPlayer player)) return;

        BlockPos pos = event.getPos();
        ServerLevel level = (ServerLevel) event.getLevel();
        BlockState state = level.getBlockState(pos);

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            SignBlockEntity sign = (SignBlockEntity) level.getBlockEntity(pos);
            if (sign != null) {
                // If it's a registered Market Shop, open the buy GUI
                if (RecruitsEconomyManager.getMarketOffers().containsKey(pos)) {
                    ItemMarketOffer offer = RecruitsEconomyManager.getMarketOffers().get(pos);
                    player.getServer().getCommands().performPrefixedCommand(player.createCommandSourceStack(), "eco buy " + offer.getSellerFactionID());
                    event.setCanceled(true);
                    return;
                }

                // If it's a PAPEL sign, register the bank
                String firstLine = getSignLine(sign, 0);
                if (firstLine.equalsIgnoreCase("PAPEL")) {
                    checkPapelSign(player, level, pos, state);
                    event.setCanceled(true);
                }
            }
        }
    }

    private String getSignLine(SignBlockEntity sign, int line) {
        CompoundTag nbt = sign.saveWithFullMetadata();
        if (nbt.contains("front_text")) {
            CompoundTag front = nbt.getCompound("front_text");
            if (front.contains("messages")) {
                ListTag messages = front.getList("messages", Tag.TAG_STRING);
                if (line < messages.size()) {
                    try {
                        Component comp = Component.Serializer.fromJson(messages.getString(line));
                        return comp != null ? comp.getString() : "";
                    } catch (Exception e) {
                        return messages.getString(line);
                    }
                }
            }
        }
        return "";
    }

    private void setSignText(SignBlockEntity sign, String[] lines, ChatFormatting[] colors, ServerLevel level) {
        CompoundTag nbt = sign.saveWithFullMetadata();
        CompoundTag front = nbt.contains("front_text") ? nbt.getCompound("front_text") : new CompoundTag();
        ListTag messages = new ListTag();
        for (int i = 0; i < 4; i++) {
            String text = i < lines.length ? lines[i] : "";
            ChatFormatting color = (colors != null && i < colors.length) ? colors[i] : ChatFormatting.BLACK;
            messages.add(net.minecraft.nbt.StringTag.valueOf(Component.Serializer.toJson(Component.literal(text).withStyle(color))));
        }
        front.put("messages", messages);
        nbt.put("front_text", front);
        sign.load(nbt);
        level.sendBlockUpdated(sign.getBlockPos(), sign.getBlockState(), sign.getBlockState(), 3);
    }

    private boolean isChestBlock(BlockState state) {
        return state.is(Blocks.CHEST) || state.is(Blocks.TRAPPED_CHEST) || state.is(Blocks.BARREL);
    }

    private void checkPapelSign(ServerPlayer player, ServerLevel level, BlockPos pos, BlockState state) {
        if (player.getTeam() == null) {
            player.sendSystemMessage(Component.literal("You must be in a faction to setup a Bank!").withStyle(ChatFormatting.RED));
            return;
        }

        String factionID = player.getTeam().getName();
        ChunkPos chunkPos = new ChunkPos(pos);
        RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

        if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
            player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Bank!").withStyle(ChatFormatting.RED));
            return;
        }

        BlockPos attachedPos;
        if (state.getBlock() instanceof WallSignBlock) {
            Direction facing = state.getValue(WallSignBlock.FACING);
            attachedPos = pos.relative(facing.getOpposite());
        } else {
            attachedPos = pos.below();
        }

        if (isChestBlock(level.getBlockState(attachedPos))) {
            RecruitsEconomyManager.addBankChest(factionID, attachedPos, level);
            player.sendSystemMessage(Component.literal("Bank Chest registered successfully!").withStyle(ChatFormatting.GREEN));
            setSignText((SignBlockEntity) level.getBlockEntity(pos), new String[]{"[BANK]", factionID, "Active", ""}, 
                    new ChatFormatting[]{ChatFormatting.GOLD, ChatFormatting.WHITE, ChatFormatting.GREEN, ChatFormatting.BLACK}, level);
        } else {
            player.sendSystemMessage(Component.literal("The sign must be attached to a chest!").withStyle(ChatFormatting.RED));
        }
    }

    private void registerMarketShop(ServerPlayer player, ServerLevel level, BlockPos pos, BlockState state, SignBlockEntity sign, CompoundTag nbt) {
        String itemID = nbt.getString("MarketItem");
        int price = nbt.getInt("MarketPrice");
        String currencyID = nbt.contains("CurrencyID") ? nbt.getString("CurrencyID") : "minecraft:emerald";

        Team team = player.getTeam();
        if (team == null) {
            player.sendSystemMessage(Component.literal("You must be in a faction to list items!").withStyle(ChatFormatting.RED));
            return;
        }

        String factionID = team.getName();
        ChunkPos chunkPos = new ChunkPos(pos);
        RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

        if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
            player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Shop!").withStyle(ChatFormatting.RED));
            return;
        }

        BlockPos attachedPos;
        if (state.getBlock() instanceof WallSignBlock) {
            Direction facing = state.getValue(WallSignBlock.FACING);
            attachedPos = pos.relative(facing.getOpposite());
        } else {
            attachedPos = pos.below();
        }

        if (isChestBlock(level.getBlockState(attachedPos))) {
            CompoundTag itemNbt = nbt.contains("ItemNbt") ? nbt.getCompound("ItemNbt") : null;
            ItemMarketOffer offer = new ItemMarketOffer(itemID, itemNbt, price, currencyID, factionID, attachedPos);
            RecruitsEconomyManager.addMarketOffer(pos, offer, level);

            String itemName = itemID;
            ResourceLocation resLoc = ResourceLocation.tryParse(itemID);
            if (resLoc != null && net.minecraftforge.registries.ForgeRegistries.ITEMS.containsKey(resLoc)) {
                itemName = new net.minecraft.world.item.ItemStack(net.minecraftforge.registries.ForgeRegistries.ITEMS.getValue(resLoc)).getHoverName().getString();
            }

            String currName = currencyID.replace("minecraft:", "");
            setSignText(sign, new String[]{"[Market]", itemName, price + " " + currName, team.getName()}, 
                    new ChatFormatting[]{ChatFormatting.GOLD, ChatFormatting.WHITE, ChatFormatting.GREEN, ChatFormatting.GRAY}, level);

            player.sendSystemMessage(Component.literal("Market Shop registered successfully!").withStyle(ChatFormatting.GREEN));
        } else {
            player.sendSystemMessage(Component.literal("The Market sign must be attached to a chest!").withStyle(ChatFormatting.RED));
        }
    }

    @SubscribeEvent
    public void onBlockBreak(BlockEvent.BreakEvent event) {
        if (event.getLevel().isClientSide() || !(event.getLevel() instanceof ServerLevel level)) return;

        BlockPos pos = event.getPos();
        BlockState state = event.getState();

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            if (RecruitsEconomyManager.getMarketOffers().containsKey(pos)) {
                ItemMarketOffer offer = RecruitsEconomyManager.getMarketOffers().get(pos);
                RecruitsEconomyManager.removeMarketOffer(pos, level);
                notifyLeader(offer.getSellerFactionID(), Component.literal("Your Market Shop at " + pos.toShortString() + " has been destroyed!").withStyle(ChatFormatting.RED), level);
            }

            for (Map.Entry<String, java.util.List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                if (entry.getValue().contains(pos)) {
                    String factionID = entry.getKey();
                    RecruitsEconomyManager.removeBankChest(factionID, pos, level);
                    notifyLeader(factionID, Component.literal("Your Bank at " + pos.toShortString() + " was removed!").withStyle(ChatFormatting.RED), level);
                    break;
                }
            }
        }

        if (isChestBlock(state)) {
            Iterator<Map.Entry<BlockPos, ItemMarketOffer>> it = RecruitsEconomyManager.getMarketOffers().entrySet().iterator();
            while (it.hasNext()) {
                Map.Entry<BlockPos, ItemMarketOffer> entry = it.next();
                if (entry.getValue().getStockChestPos().equals(pos)) {
                    it.remove();
                    notifyLeader(entry.getValue().getSellerFactionID(), Component.literal("Shop at " + entry.getKey().toShortString() + " removed (chest broken)!").withStyle(ChatFormatting.RED), level);
                }
            }
            for (Map.Entry<String, java.util.List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                if (entry.getValue().contains(pos)) {
                    RecruitsEconomyManager.removeBankChest(entry.getKey(), pos, level);
                    notifyLeader(entry.getKey(), Component.literal("Bank at " + pos.toShortString() + " destroyed!").withStyle(ChatFormatting.RED), level);
                    break;
                }
            }
        }
    }

    private void notifyLeader(String factionID, Component message, ServerLevel level) {
        RecruitsFaction faction = FactionEvents.recruitsFactionManager.getFactionByStringID(factionID);
        if (faction != null && faction.getTeamLeaderUUID() != null) {
            ServerPlayer leader = level.getServer().getPlayerList().getPlayer(faction.getTeamLeaderUUID());
            if (leader != null) leader.sendSystemMessage(message);
        }
    }

    @SubscribeEvent
    public void onPlayerJoin(EntityJoinLevelEvent event) {
        if (event.getLevel().isClientSide() || !(event.getEntity() instanceof ServerPlayer player)) return;
        RecruitsEconomyManager.syncToPlayer(player);
    }

    @SubscribeEvent
    public void onServerTick(TickEvent.ServerTickEvent event) {
        if (event.phase != TickEvent.Phase.END) return;
        if (++tickCounter >= 1000) {
            tickCounter = 0;
            long now = System.currentTimeMillis();
            if (RecruitsEconomyManager.getPendingRequests().entrySet().removeIf(e -> now > e.getValue())) {
                RecruitsEconomyManager.save(event.getServer().overworld());
                RecruitsEconomyManager.syncAll();
            }
        }
    }
