        int price = nbt.getInt("MarketPrice");
        String currencyID = nbt.contains("CurrencyID") ? nbt.getString("CurrencyID") : "minecraft:emerald";

        Team team = player.getTeam();
        if (team == null) {
            player.sendSystemMessage(Component.literal("You must be in a faction to list items!").withStyle(ChatFormatting.RED));
            return;
        }

        String factionID = team.getName();
        ChunkPos chunkPos = new ChunkPos(pos);
        RecruitsClaim claim = ClaimEvents.recruitsClaimManager.getClaim(chunkPos);

        if (claim == null || claim.getOwnerFaction() == null || !claim.getOwnerFaction().getStringID().equals(factionID)) {
            player.sendSystemMessage(Component.literal("This chunk must be claimed by your faction to setup a Shop!").withStyle(ChatFormatting.RED));
            return;
        }

        BlockPos attachedPos;
        if (state.getBlock() instanceof WallSignBlock) {
            Direction facing = state.getValue(WallSignBlock.FACING);
            attachedPos = pos.relative(facing.getOpposite());
        } else {
            attachedPos = pos.below();
        }

        if (isChestBlock(level.getBlockState(attachedPos))) {
            CompoundTag itemNbt = nbt.contains("ItemNbt") ? nbt.getCompound("ItemNbt") : null;
            ItemMarketOffer offer = new ItemMarketOffer(itemID, itemNbt, price, currencyID, factionID, attachedPos);
            RecruitsEconomyManager.addMarketOffer(pos, offer, level);

            String itemName = itemID;
            ResourceLocation resLoc = ResourceLocation.tryParse(itemID);
            if (resLoc != null && net.minecraftforge.registries.ForgeRegistries.ITEMS.containsKey(resLoc)) {
                itemName = new net.minecraft.world.item.ItemStack(net.minecraftforge.registries.ForgeRegistries.ITEMS.getValue(resLoc)).getHoverName().getString();
            }

            String currName = currencyID.replace("minecraft:", "");
            setSignText(sign, new String[]{"[Market]", itemName, price + " " + currName, team.getName()}, 
                    new ChatFormatting[]{ChatFormatting.GOLD, ChatFormatting.WHITE, ChatFormatting.GREEN, ChatFormatting.GRAY}, level);

            player.sendSystemMessage(Component.literal("Market Shop registered successfully!").withStyle(ChatFormatting.GREEN));
        } else {
            player.sendSystemMessage(Component.literal("The Market sign must be attached to a chest!").withStyle(ChatFormatting.RED));
        }
    }

    @SubscribeEvent
    public void onBlockBreak(BlockEvent.BreakEvent event) {
        if (event.getLevel().isClientSide() || !(event.getLevel() instanceof ServerLevel level)) return;

        BlockPos pos = event.getPos();
        BlockState state = event.getState();

        if (state.getBlock() instanceof net.minecraft.world.level.block.SignBlock) {
            if (RecruitsEconomyManager.getMarketOffers().containsKey(pos)) {
                ItemMarketOffer offer = RecruitsEconomyManager.getMarketOffers().get(pos);
                RecruitsEconomyManager.removeMarketOffer(pos, level);
                notifyLeader(offer.getSellerFactionID(), Component.literal("Your Market Shop at " + pos.toShortString() + " has been destroyed!").withStyle(ChatFormatting.RED), level);
            }

            for (Map.Entry<String, java.util.List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                if (entry.getValue().contains(pos)) {
                    String factionID = entry.getKey();
                    RecruitsEconomyManager.removeBankChest(factionID, pos, level);
                    notifyLeader(factionID, Component.literal("Your Bank at " + pos.toShortString() + " was removed!").withStyle(ChatFormatting.RED), level);
                    break;
                }
            }
        }

        if (isChestBlock(state)) {
            Iterator<Map.Entry<BlockPos, ItemMarketOffer>> it = RecruitsEconomyManager.getMarketOffers().entrySet().iterator();
            while (it.hasNext()) {
                Map.Entry<BlockPos, ItemMarketOffer> entry = it.next();
                if (entry.getValue().getStockChestPos().equals(pos)) {
                    it.remove();
                    notifyLeader(entry.getValue().getSellerFactionID(), Component.literal("Shop at " + entry.getKey().toShortString() + " removed (chest broken)!").withStyle(ChatFormatting.RED), level);
                }
            }
            for (Map.Entry<String, java.util.List<BlockPos>> entry : RecruitsEconomyManager.getBankChests().entrySet()) {
                if (entry.getValue().contains(pos)) {
                    RecruitsEconomyManager.removeBankChest(entry.getKey(), pos, level);
                    notifyLeader(entry.getKey(), Component.literal("Bank at " + pos.toShortString() + " destroyed!").withStyle(ChatFormatting.RED), level);
                    break;
                }
            }
        }
    }

    private void notifyLeader(String factionID, Component message, ServerLevel level) {
        RecruitsFaction faction = FactionEvents.recruitsFactionManager.getFactionByStringID(factionID);
        if (faction != null && faction.getTeamLeaderUUID() != null) {
            ServerPlayer leader = level.getServer().getPlayerList().getPlayer(faction.getTeamLeaderUUID());
            if (leader != null) leader.sendSystemMessage(message);
        }
    }

    @SubscribeEvent
    public void onPlayerJoin(EntityJoinLevelEvent event) {
        if (event.getLevel().isClientSide() || !(event.getEntity() instanceof ServerPlayer player)) return;
        RecruitsEconomyManager.syncToPlayer(player);
        TradeRouteManager.syncToPlayer(player);
    }

    @SubscribeEvent
    public void onServerTick(TickEvent.ServerTickEvent event) {
        if (event.phase != TickEvent.Phase.END) return;
        if (++tickCounter >= 1000) {
            tickCounter = 0;
            long now = System.currentTimeMillis();
            if (RecruitsEconomyManager.getPendingRequests().entrySet().removeIf(e -> now > e.getValue())) {
                RecruitsEconomyManager.save(event.getServer().overworld());
                RecruitsEconomyManager.syncAll();
            }
        }
    }
}

package com.talhanation.recruits.client.gui.worldmap;

import com.talhanation.recruits.rrextra.TradeRoute;
import com.talhanation.recruits.rrextra.client.TradeRouteClientManager;
import net.minecraft.client.gui.GuiGraphics;
import net.minecraft.world.level.ChunkPos;

public class TradeRouteRenderer {
    public static void renderRoutes(GuiGraphics guiGraphics, double offsetX, double offsetZ, double scale) {
        for (TradeRoute route : TradeRouteClientManager.getAllRoutes()) {
            for (ChunkPos pos : route.getPath()) {
                renderChunkBorder(guiGraphics, pos, route, offsetX, offsetZ, scale);
            }
        }
    }

    private static void renderChunkBorder(GuiGraphics guiGraphics, ChunkPos pos, TradeRoute route, double offsetX, double offsetZ, double scale) {
        int x1 = (int) (offsetX + pos.x * 16 * scale);
        int z1 = (int) (offsetZ + pos.z * 16 * scale);
        int size = (int) (16 * scale);

        int color = 0xFFFFD700; // Gold/Yellow default
        boolean dashed = true;

        if (route.isVulnerable()) {
            // Pulsing red
            float pulse = (float) ((Math.sin(System.currentTimeMillis() / 200.0) + 1.0) / 2.0);
            int red = (int) (155 + 100 * pulse);
            color = (0xFF << 24) | (red << 16);
            dashed = false; // Solid pulsing for vulnerability
        } else if (route.getGracePeriodEndTime() > System.currentTimeMillis()) {
            // Translucent grey for grace period
            color = 0x80808080;
        }

        if (dashed) {
            drawDashedRect(guiGraphics, x1, z1, size, size, color);
        } else {
            guiGraphics.renderOutline(x1, z1, size, size, color);
        }
    }

    private static void drawDashedRect(GuiGraphics guiGraphics, int x, int z, int w, int h, int color) {
        int dashLength = 4;
        // Top
        for (int i = 0; i < w; i += dashLength * 2) {
            guiGraphics.fill(x + i, z, x + Math.min(i + dashLength, w), z + 1, color);
        }
        // Bottom
        for (int i = 0; i < w; i += dashLength * 2) {
            guiGraphics.fill(x + i, z + h - 1, x + Math.min(i + dashLength, w), z + h, color);
        }
        // Left
        for (int i = 0; i < h; i += dashLength * 2) {
            guiGraphics.fill(x, z + i, x + 1, z + Math.min(i + dashLength, h), color);
        }
        // Right
        for (int i = 0; i < h; i += dashLength * 2) {
            guiGraphics.fill(x + w - 1, z + i, x + w, z + Math.min(i + dashLength, h), color);
        }
    }
}

