import net.minecraft.nbt.Tag;
import net.minecraft.world.level.ChunkPos;

import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

public class TradeRoute {
    private final UUID uuid;
    private final String factionA;
    private final String factionB;
    private final List<ChunkPos> path;
    private int health;
    private boolean isVulnerable;
    private long gracePeriodEndTime;

    public TradeRoute(UUID uuid, String factionA, String factionB, List<ChunkPos> path, int health, boolean isVulnerable, long gracePeriodEndTime) {
        this.uuid = uuid;
        this.factionA = factionA;
        this.factionB = factionB;
        this.path = path;
        this.health = health;
        this.isVulnerable = isVulnerable;
        this.gracePeriodEndTime = gracePeriodEndTime;
    }

    public UUID getUuid() { return uuid; }
    public String getFactionA() { return factionA; }
    public String getFactionB() { return factionB; }
    public List<ChunkPos> getPath() { return path; }
    public int getHealth() { return health; }
    public void setHealth(int health) { this.health = health; }
    public boolean isVulnerable() { return isVulnerable; }
    public void setVulnerable(boolean vulnerable) { isVulnerable = vulnerable; }
    public long getGracePeriodEndTime() { return gracePeriodEndTime; }
    public void setGracePeriodEndTime(long gracePeriodEndTime) { this.gracePeriodEndTime = gracePeriodEndTime; }

    public CompoundTag toNBT() {
        CompoundTag nbt = new CompoundTag();
        nbt.putUUID("UUID", uuid);
        nbt.putString("FactionA", factionA);
        nbt.putString("FactionB", factionB);

        ListTag pathTag = new ListTag();
        for (ChunkPos pos : path) {
            CompoundTag posTag = new CompoundTag();
            posTag.putInt("x", pos.x);
            posTag.putInt("z", pos.z);
            pathTag.add(posTag);
        }
        nbt.put("Path", pathTag);

        nbt.putInt("Health", health);
        nbt.putBoolean("IsVulnerable", isVulnerable);
        nbt.putLong("GracePeriodEndTime", gracePeriodEndTime);
        return nbt;
    }

    public static TradeRoute fromNBT(CompoundTag nbt) {
        UUID uuid = nbt.getUUID("UUID");
        String factionA = nbt.getString("FactionA");
        String factionB = nbt.getString("FactionB");

        ListTag pathTag = nbt.getList("Path", Tag.TAG_COMPOUND);
        List<ChunkPos> path = new ArrayList<>();
        for (int i = 0; i < pathTag.size(); i++) {
            CompoundTag posTag = pathTag.getCompound(i);
            path.add(new ChunkPos(posTag.getInt("x"), posTag.getInt("z")));
        }

        int health = nbt.getInt("Health");
        boolean isVulnerable = nbt.getBoolean("IsVulnerable");
        long gracePeriodEndTime = nbt.getLong("GracePeriodEndTime");

        return new TradeRoute(uuid, factionA, factionB, path, health, isVulnerable, gracePeriodEndTime);
    }
}

