import java.util.List;

public class TradeRouteSaveData extends SavedData {
    private List<TradeRoute> routes = new ArrayList<>();

    public static TradeRouteSaveData get(ServerLevel level) {
        return level.getDataStorage().computeIfAbsent(TradeRouteSaveData::load, TradeRouteSaveData::new, "rrextra_routes");
    }

    public TradeRouteSaveData() {}

    public TradeRouteSaveData(CompoundTag nbt) {
        ListTag list = nbt.getList("Routes", Tag.TAG_COMPOUND);
        for (int i = 0; i < list.size(); i++) {
            routes.add(TradeRoute.fromNBT(list.getCompound(i)));
        }
    }

    public static TradeRouteSaveData load(CompoundTag nbt) {
        return new TradeRouteSaveData(nbt);
    }

    @Override
    public CompoundTag save(CompoundTag nbt) {
        ListTag list = new ListTag();
        for (TradeRoute route : routes) {
            list.add(route.toNBT());
        }
        nbt.put("Routes", list);
        return nbt;
    }

    public void setRoutes(List<TradeRoute> routes) {
        this.routes = new ArrayList<>(routes);
        setDirty();
    }

    public List<TradeRoute> getRoutes() {
        return routes;
    }
}

