package com.talhanation.recruits.client.gui.worldmap;

import com.talhanation.recruits.rrextra.TradeRoute;
import com.talhanation.recruits.rrextra.client.TradeRouteClientManager;
import net.minecraft.client.gui.GuiGraphics;
import net.minecraft.world.level.ChunkPos;

public class TradeRouteRenderer {
    public static void renderRoutes(GuiGraphics guiGraphics, double offsetX, double offsetZ, double scale) {
        java.util.List<TradeRoute> routes = TradeRouteClientManager.getAllRoutes();
        if (routes.isEmpty()) return;

        for (TradeRoute route : routes) {
            for (ChunkPos pos : route.getPath()) {
                renderChunkBorder(guiGraphics, pos, route, offsetX, offsetZ, scale);
            }
        }
    }

    private static void renderChunkBorder(GuiGraphics guiGraphics, ChunkPos pos, TradeRoute route, double offsetX, double offsetZ, double scale) {
        double worldX1 = pos.x * 16.0;
        double worldZ1 = pos.z * 16.0;

        int x1 = (int) Math.floor(offsetX + worldX1 * scale);
        int z1 = (int) Math.floor(offsetZ + worldZ1 * scale);
        int x2 = (int) Math.floor(offsetX + (worldX1 + 16.0) * scale);
        int z2 = (int) Math.floor(offsetZ + (worldZ1 + 16.0) * scale);

        int w = x2 - x1;
        int h = z2 - z1;

        if (w <= 0) w = 1;
        if (h <= 0) h = 1;

        int color = 0xFFFFD700; // Gold/Yellow default
        boolean dashed = true;

        if (route.isVulnerable()) {
            // Pulsing red
            float pulse = (float) ((Math.sin(System.currentTimeMillis() / 200.0) + 1.0) / 2.0);
            int red = (int) (155 + 100 * pulse);
            color = (0xFF << 24) | (red << 16) | (0x00 << 8) | 0x00;
            dashed = false; // Solid pulsing for vulnerability
        } else if (route.getGracePeriodEndTime() > 0 && route.getGracePeriodEndTime() > System.currentTimeMillis()) {
            // Translucent grey for grace period
            color = 0x80808080;
        }

        // Always draw a faint fill so it's easier to see
        int fillColor = (color & 0x00FFFFFF) | (0x30 << 24);
        guiGraphics.fill(x1, z1, x2, z2, fillColor);

        if (dashed) {
            drawDashedRect(guiGraphics, x1, z1, w, h, color);
        } else {
            guiGraphics.renderOutline(x1, z1, w, h, color);
        }
    }

    private static void drawDashedRect(GuiGraphics guiGraphics, int x, int z, int w, int h, int color) {
        int dashLength = 4;
        if (w < 8 || h < 8) {
            guiGraphics.renderOutline(x, z, w, h, color);
            return;
        }

        // Top
        for (int i = 0; i < w; i += dashLength * 2) {
            guiGraphics.fill(x + i, z, x + Math.min(i + dashLength, w), z + 1, color);
        }
        // Bottom
        for (int i = 0; i < w; i += dashLength * 2) {
            guiGraphics.fill(x + i, z + h - 1, x + Math.min(i + dashLength, w), z + h, color);
        }
        // Left
        for (int i = 0; i < h; i += dashLength * 2) {
            guiGraphics.fill(x, z + i, x + 1, z + Math.min(i + dashLength, h), color);
        }
        // Right
        for (int i = 0; i < h; i += dashLength * 2) {
            guiGraphics.fill(x + w - 1, z + i, x + w, z + Math.min(i + dashLength, h), color);
        }
    }
}

